import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Store {
  id: string;
  name: string;
  category: string;
  logo: string;
  rating: number;
  address: string;
  isPartner: boolean;
}

export interface Promotion {
  id: string;
  storeId: string;
  storeName: string;
  storeLogo: string;
  videoUrl?: string;
  imageUrl: string;
  description: string;
  discount: string;
  expiresAt: string;
  likes: number;
  saved: boolean;
}

export type ViewType = 'FEED' | 'EXPLORE' | 'MERCHANT' | 'PROFILE';

import React from 'react';
import { ViewType } from '../types';
import { Home, Search, Store as StoreIcon, User } from 'lucide-react';

interface LayoutProps {
  children: React.ReactNode;
  activeView: ViewType;
  onViewChange: (view: ViewType) => void;
}

const Layout: React.FC<LayoutProps> = ({ children, activeView, onViewChange }) => {
  return (
    <div className="flex flex-col h-screen max-w-md mx-auto bg-white shadow-xl relative overflow-hidden">
      {/* Main Content Area */}
      <main className="flex-1 overflow-hidden">
        {children}
      </main>

      {/* Bottom Navigation */}
      <nav className="h-16 bg-white border-t border-gray-100 flex items-center justify-around px-2 z-50">
        <button 
          onClick={() => onViewChange('FEED')}
          className={`flex flex-col items-center gap-1 transition-colors ${activeView === 'FEED' ? 'text-indigo-600' : 'text-gray-400'}`}
        >
          <Home size={24} strokeWidth={activeView === 'FEED' ? 2.5 : 2} />
          <span className="text-[10px] font-medium">Início</span>
        </button>

        <button 
          onClick={() => onViewChange('EXPLORE')}
          className={`flex flex-col items-center gap-1 transition-colors ${activeView === 'EXPLORE' ? 'text-indigo-600' : 'text-gray-400'}`}
        >
          <Search size={24} strokeWidth={activeView === 'EXPLORE' ? 2.5 : 2} />
          <span className="text-[10px] font-medium">Explorar</span>
        </button>

        <button 
          onClick={() => onViewChange('MERCHANT')}
          className={`flex flex-col items-center gap-1 transition-colors ${activeView === 'MERCHANT' ? 'text-indigo-600' : 'text-gray-400'}`}
        >
          <StoreIcon size={24} strokeWidth={activeView === 'MERCHANT' ? 2.5 : 2} />
          <span className="text-[10px] font-medium">Lojista</span>
        </button>

        <button 
          onClick={() => onViewChange('PROFILE')}
          className={`flex flex-col items-center gap-1 transition-colors ${activeView === 'PROFILE' ? 'text-indigo-600' : 'text-gray-400'}`}
