import { Heart, MessageCircle, Share2, Bookmark, MapPin } from 'lucide-react';

interface ReelCardProps {
  promotion: Promotion;
}

const ReelCard: React.FC<ReelCardProps> = ({ promotion }) => {
  const [isLiked, setIsLiked] = useState(false);
  const [isSaved, setIsSaved] = useState(promotion.saved);

  return (
    <div className="relative h-full w-full snap-start bg-black overflow-hidden flex flex-col justify-center">
      {/* Background Image/Video */}
      <img 
        src={promotion.imageUrl} 
        alt={promotion.description}
        className="absolute inset-0 w-full h-full object-cover opacity-80"
      />

      {/* Gradient Overlay for Readability */}
      <div className="absolute inset-0 bg-gradient-to-b from-transparent via-transparent to-black/80" />

      {/* Side Actions */}
      <div className="absolute right-4 bottom-24 flex flex-col items-center gap-6 z-20">
        <button 
          onClick={() => setIsLiked(!isLiked)}
          className="flex flex-col items-center group"
        >
          <div className={`p-2 rounded-full transition-all ${isLiked ? 'bg-rose-500 scale-110' : 'bg-black/20 group-hover:bg-black/40'}`}>
            <Heart size={28} className="text-white fill-current" fill={isLiked ? 'currentColor' : 'none'} />
          </div>
          <span className="text-white text-xs mt-1 font-semibold">{promotion.likes + (isLiked ? 1 : 0)}</span>
        </button>

        <button className="flex flex-col items-center group">
          <div className="p-2 rounded-full bg-black/20 group-hover:bg-black/40 transition-all">
            <MessageCircle size={28} className="text-white" />
          </div>
          <span className="text-white text-xs mt-1 font-semibold">12</span>
        </button>

        <button 
          onClick={() => setIsSaved(!isSaved)}
          className="flex flex-col items-center group"
        >
          <div className={`p-2 rounded-full transition-all ${isSaved ? 'bg-indigo-500 scale-110' : 'bg-black/20 group-hover:bg-black/40'}`}>
            <Bookmark size={28} className="text-white fill-current" fill={isSaved ? 'currentColor' : 'none'} />
          </div>
          <span className="text-white text-xs mt-1 font-semibold">{isSaved ? 'Salvo' : 'Salvar'}</span>
        </button>

        <button className="flex flex-col items-center group">
          <div className="p-2 rounded-full bg-black/20 group-hover:bg-black/40 transition-all">
            <Share2 size={28} className="text-white" />
