import { useState, useEffect } from 'react';
import { collection, query, onSnapshot, orderBy } from 'firebase/firestore';
import { db, isFirebaseConfigured } from '../firebase';
import { Promotion } from '../types';
import { MOCK_PROMOTIONS } from '../constants';

export const usePromotions = () => {
  const [promotions, setPromotions] = useState<Promotion[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [isUsingMock, setIsUsingMock] = useState(false);

  useEffect(() => {
    // Se não estiver configurado, usa mock data imediatamente para não quebrar a UI
    if (!isFirebaseConfigured) {
      setPromotions(MOCK_PROMOTIONS);
      setIsUsingMock(true);
      setLoading(false);
      return;
    }

    const q = query(collection(db, "promotions"), orderBy("createdAt", "desc"));

    const unsubscribe = onSnapshot(q, (querySnapshot) => {
      const promos: Promotion[] = [];
      querySnapshot.forEach((doc) => {
        promos.push({ id: doc.id, ...doc.data() } as Promotion);
      });

      // Se o banco estiver vazio, podemos opcionalmente mostrar os mocks para "rechear" o app
      if (promos.length === 0) {
        setPromotions(MOCK_PROMOTIONS);
        setIsUsingMock(true);
      } else {
        setPromotions(promos);
        setIsUsingMock(false);
      }

      setLoading(false);
      setError(null);
    }, (err) => {
      console.error("Erro Firestore:", err);
      setError(err.message);

      // Fallback para mocks em caso de erro de permissão (ex: chaves inválidas)
      setPromotions(MOCK_PROMOTIONS);
      setIsUsingMock(true);
      setLoading(false);
    });

    return () => unsubscribe();
  }, []);

  return { promotions, loading, error, isUsingMock };
};

