import React, { useState } from 'react';
import { collection, addDoc, serverTimestamp } from 'firebase/firestore';
import { ref, uploadBytes, getDownloadURL } from 'firebase/storage';
import { db, storage, isFirebaseConfigured } from '../firebase';
import { Plus, BarChart2, MessageSquare, CheckCircle, Loader2, X, AlertTriangle } from 'lucide-react';

const MerchantDashboard: React.FC = () => {
  const [showModal, setShowModal] = useState(false);
  const [loading, setLoading] = useState(false);
  const [formData, setFormData] = useState({
    description: '',
    discount: '',
    expiresAt: ''
  });
  const [file, setFile] = useState<File | null>(null);

  const handleCreatePromo = async () => {
    // 1. Verificações Básicas de Formulário
    if (!formData.description || !file) {
      alert("⚠️ Por favor, preencha a descrição e anexe uma imagem ou vídeo.");
      return;
    }

    // 2. Verificação de Conexão com Firebase
    if (!isFirebaseConfigured || !db || !storage) {
      alert("❌ Firebase não configurado. Verifique se você seguiu os passos de configuração no arquivo firebase.ts");
      return;
    }

    setLoading(true);
    try {
      console.log("Iniciando upload para o Storage...");
      // 3. Upload do Arquivo
      const fileExt = file.name.split('.').pop();
      const fileName = `promo_${Date.now()}.${fileExt}`;
      const storageRef = ref(storage, `promotions/${fileName}`);

      const snapshot = await uploadBytes(storageRef, file);
      const downloadUrl = await getDownloadURL(snapshot.ref);
      console.log("Upload concluído! URL:", downloadUrl);

      // 4. Salvar no Firestore
      console.log("Salvando documento no Firestore...");
      await addDoc(collection(db, "promotions"), {
        description: formData.description,
        discount: formData.discount || "Oferta Especial",
        expiresAt: formData.expiresAt || "Até durar o estoque",
        imageUrl: downloadUrl,
        storeId: 's1', 
        storeName: 'Pizzaria do Bairro',
        storeLogo: 'https://picsum.photos/seed/pizza/100/100',
        likes: 0,
        saved: false,
        createdAt: serverTimestamp()
      });

      console.log("Promoção publicada com sucesso!");
      setShowModal(false);
      setFormData({ description: '', discount: '', expiresAt: '' });
      setFile(null);
      alert("🚀 Sucesso! Sua promoção já está no ar para toda a cidade.");
    } catch (error: any) {
      console.error("Erro completo ao publicar:", error);
      let errorMessage = "Erro desconhecido ao publicar.";

      if (error.code === 'storage/unauthorized') {
        errorMessage = "Erro de Permissão no Storage: Verifique se as Regras do Firebase Storage estão no modo de teste (allow read, write: if true).";
      } else if (error.code === 'permission-denied') {
        errorMessage = "Erro de Permissão no Firestore: Verifique se as Regras do Firestore Database estão no modo de teste.";
      } else {
        errorMessage = `Falha na publicação: ${error.message || error}`;
      }

      alert(errorMessage);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="p-4 h-full bg-gray-50 overflow-y-auto pb-20">
      <div className="flex items-center justify-between mb-8">
        <div>
          <h1 className="text-2xl font-bold text-gray-800">Painel do Lojista</h1>
          <p className="text-sm text-gray-500">Gerencie suas ofertas reais</p>
        </div>
        <div className="bg-green-100 text-green-700 p-2 rounded-full">
          <CheckCircle size={24} />
        </div>
      </div>

      {!isFirebaseConfigured && (
        <div className="mb-6 p-4 bg-amber-50 border border-amber-200 rounded-2xl flex gap-3 items-start text-amber-800">
          <AlertTriangle className="shrink-0 mt-0.5" size={18} />
