import React, { useState } from 'react';
import { collection, addDoc, serverTimestamp } from 'firebase/firestore';
import { ref, uploadBytes, getDownloadURL } from 'firebase/storage';
import { db, storage, isFirebaseConfigured } from '../firebase';
import { Plus, BarChart2, MessageSquare, CheckCircle, Loader2, X, AlertTriangle } from 'lucide-react';

const MerchantDashboard: React.FC = () => {
  const [showModal, setShowModal] = useState(false);
  const [loading, setLoading] = useState(false);
  const [formData, setFormData] = useState({
    description: '',
    discount: '',
    expiresAt: ''
  });
  const [file, setFile] = useState<File | null>(null);

  const handleCreatePromo = async () => {
    if (!formData.description || !file) {
      alert("⚠️ Preencha a descrição e escolha uma foto ou vídeo.");
      return;
    }

    if (!isFirebaseConfigured || !db || !storage) {
      alert("❌ Firebase não configurado corretamente. Verifique as chaves no arquivo firebase.ts");
      return;
    }

    setLoading(true);
    try {
      // 1. Upload do Arquivo para o Storage
      const fileExt = file.name.split('.').pop();
      const fileName = `promo_${Date.now()}.${fileExt}`;
      const storageRef = ref(storage, `promotions/${fileName}`);

      const snapshot = await uploadBytes(storageRef, file);
      const downloadUrl = await getDownloadURL(snapshot.ref);

      // 2. Salvar metadados no Firestore
      await addDoc(collection(db, "promotions"), {
        description: formData.description,
        discount: formData.discount || "Promoção",
        expiresAt: formData.expiresAt || "Indeterminado",
        imageUrl: downloadUrl,
        storeId: 'lojista_demo', 
        storeName: 'Sua Loja Aqui',
        storeLogo: 'https://picsum.photos/seed/shop/100/100',
        likes: 0,
        saved: false,
        createdAt: serverTimestamp()
      });

      setShowModal(false);
      setFormData({ description: '', discount: '', expiresAt: '' });
      setFile(null);
      alert("🚀 Promoção publicada com sucesso!");
    } catch (error: any) {
      console.error("Erro na publicação:", error);

      let msg = "Falha ao publicar. ";
      if (error.code === 'storage/unauthorized') {
        msg += "Verifique se você ativou o Firebase Storage e liberou as REGRAS para escrita.";
      } else if (error.code === 'permission-denied') {
        msg += "Verifique se as REGRAS do Firestore permitem gravação.";
      } else {
        msg += error.message;
      }
      alert(msg);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="p-4 h-full bg-gray-50 overflow-y-auto pb-20">
      <div className="flex items-center justify-between mb-8">
        <div className="text-left">
          <h1 className="text-2xl font-bold text-gray-800">Painel do Lojista</h1>
          <p className="text-sm text-gray-500">Controle suas ofertas</p>
        </div>
        <div className="bg-indigo-100 text-indigo-700 p-2 rounded-full">
          <CheckCircle size={24} />
        </div>
      </div>

      {!isFirebaseConfigured && (
        <div className="mb-6 p-4 bg-amber-50 border border-amber-200 rounded-2xl flex gap-3 items-start text-amber-800 text-left">
          <AlertTriangle className="shrink-0 mt-0.5" size={18} />
          <div className="text-xs">
            <p className="font-bold uppercase mb-1 text-[10px]">Atenção</p>
            <p>O Firebase ainda não está conectado. Suas publicações não serão salvas na nuvem.</p>
          </div>
        </div>
      )}

      <div className="grid grid-cols-2 gap-4 mb-8 text-left">
        <div className="bg-white p-4 rounded-2xl border border-gray-100 shadow-sm">
          <p className="text-[10px] text-gray-500 uppercase font-bold tracking-widest mb-1">Visualizações</p>
          <p className="text-xl font-black text-indigo-600">--</p>
        </div>
        <div className="bg-white p-4 rounded-2xl border border-gray-100 shadow-sm">
          <p className="text-[10px] text-gray-500 uppercase font-bold tracking-widest mb-1">Cliques</p>
          <p className="text-xl font-black text-indigo-600">--</p>
        </div>
      </div>

      <button 
        onClick={() => setShowModal(true)}
        className="w-full bg-indigo-600 hover:bg-indigo-700 text-white font-bold py-4 rounded-2xl flex items-center justify-center gap-2 shadow-lg shadow-indigo-200 transition-all mb-8"
      >
        <Plus size={24} />
        NOVA PROMOÇÃO
      </button>

      <div className="space-y-4">
        <h2 className="text-xs font-bold text-gray-500 uppercase tracking-widest text-left">Minha Empresa</h2>
        <div className="bg-white rounded-2xl border border-gray-100 shadow-sm overflow-hidden">
          <button className="w-full flex items-center gap-4 p-4 hover:bg-gray-50 border-b border-gray-50 transition-colors text-left">
            <div className="bg-blue-100 p-2 rounded-lg text-blue-600"><BarChart2 size={20} /></div>
            <span className="font-semibold text-gray-700 flex-1 text-sm">Desempenho</span>
          </button>
          <button className="w-full flex items-center gap-4 p-4 hover:bg-gray-50 transition-colors text-left">
            <div className="bg-purple-100 p-2 rounded-lg text-purple-600"><MessageSquare size={20} /></div>
            <span className="font-semibold text-gray-700 flex-1 text-sm">Falar com Suporte</span>
          </button>
        </div>
      </div>

      {showModal && (
        <div className="fixed inset-0 z-[100] bg-black/80 flex items-end sm:items-center justify-center p-4 backdrop-blur-md animate-fade-in">
          <div className="bg-white w-full max-w-sm rounded-t-3xl sm:rounded-3xl p-6 relative shadow-2xl">
            <button 
              onClick={() => !loading && setShowModal(false)} 
              className="absolute top-4 right-4 text-gray-400 hover:text-gray-600 p-2"
              disabled={loading}
            >
              <X size={24} />
            </button>
            <div className="text-left">
              <h3 className="text-xl font-bold mb-1">Publicar Oferta</h3>
              <p className="text-sm text-gray-500 mb-6">Esta oferta será vista por toda a cidade.</p>
            </div>

            <div className="space-y-4 mb-8 text-left">
              <div>
                <label className="text-xs font-bold text-gray-400 uppercase tracking-tighter">Descrição</label>
                <textarea 
                  value={formData.description}
                  onChange={(e) => setFormData({...formData, description: e.target.value})}
                  className="w-full bg-gray-50 border border-gray-200 rounded-xl p-3 text-sm focus:ring-2 focus:ring-indigo-500 outline-none mt-1"
                  placeholder="O que está em promoção?"
                  rows={3}
                  disabled={loading}
                />
              </div>
              <div className="flex gap-4">
                <div className="flex-1">
                  <label className="text-xs font-bold text-gray-400 uppercase tracking-tighter">Desconto</label>
                  <input 
                    value={formData.discount}
                    onChange={(e) => setFormData({...formData, discount: e.target.value})}
                    placeholder="Ex: 50% OFF"
                    disabled={loading}
                    type="text" className="w-full bg-gray-50 border border-gray-200 rounded-xl p-3 text-sm focus:ring-2 focus:ring-indigo-500 outline-none mt-1" 
                  />
                </div>
                <div className="flex-1">
                   <label className="text-xs font-bold text-gray-400 uppercase tracking-tighter">Validade</label>
                   <input 
                    value={formData.expiresAt}
                    onChange={(e) => setFormData({...formData, expiresAt: e.target.value})}
                    type="date" 
                    disabled={loading}
                    className="w-full bg-gray-50 border border-gray-200 rounded-xl p-3 text-sm focus:ring-2 focus:ring-indigo-500 outline-none mt-1" 
                   />
                </div>
              </div>

              <div className="relative border-2 border-dashed border-gray-200 rounded-2xl p-6 flex flex-col items-center justify-center gap-2 cursor-pointer hover:bg-gray-50 transition-colors overflow-hidden min-h-[120px]">
                <input 
                  type="file" 
                  accept="image/*,video/*" 
                  disabled={loading}
                  onChange={(e) => setFile(e.target.files?.[0] || null)}
                  className="absolute inset-0 opacity-0 cursor-pointer z-10"
                />
                {file ? (
                  <div className="text-center">
                    <CheckCircle className="text-green-500 mx-auto mb-1" />
                    <span className="text-[11px] font-bold text-gray-700 truncate max-w-[200px] block px-2">{file.name}</span>
                  </div>
                ) : (
                  <>
                    <Plus className="text-gray-300" size={32} />
                    <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest text-center">Selecionar Vídeo/Foto</span>
                  </>
                )}
              </div>
            </div>

            <button 
              onClick={handleCreatePromo}
              disabled={loading}
              className="w-full py-4 bg-indigo-600 rounded-xl font-black text-white shadow-xl shadow-indigo-100 flex items-center justify-center gap-3 disabled:opacity-70 disabled:cursor-not-allowed transition-all active:scale-[0.98]"
            >
              {loading ? (
                <>
                  <Loader2 className="animate-spin" size={20} />
                  <span>PUBLICANDO...</span>
                </>
              ) : (
                'LANÇAR OFERTA'
              )}
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

export default MerchantDashboard;

