service cloud.firestore {
  match /databases/{database}/documents {
    // Regras para a coleção de promoções
    match /promotions/{promotionId} {
      // Qualquer pessoa pode ver as promoções na cidade
      allow read: if true;

      // Apenas usuários autenticados (lojistas) podem criar ou editar promoções
      allow create, update, delete: if request.auth != null;
    }

    // Regras para outras coleções (opcional, mantendo fechado por padrão)
    match /{document=**} {
      allow read, write: if request.auth != null;
    }
  }
}

rules_version = '2';
service firebase.storage {
  match /b/{bucket}/o {
    match /promotions/{allPaths=**} {
      // Qualquer pessoa pode ver as imagens/vídeos das promoções
      allow read: if true;

      // Apenas usuários autenticados podem fazer upload de novas mídias
      allow write: if request.auth != null;
    }
  }
}

import React, { useState, useEffect } from 'react';
import { collection, addDoc, serverTimestamp } from 'firebase/firestore';
import { ref, uploadBytes, getDownloadURL } from 'firebase/storage';
import { signInAnonymously, onAuthStateChanged, User } from 'firebase/auth';
import { db, storage, auth, isFirebaseConfigured } from '../firebase';
import { Plus, BarChart2, MessageSquare, CheckCircle, Loader2, X, AlertTriangle, ShieldCheck } from 'lucide-react';

const MerchantDashboard: React.FC = () => {
  const [showModal, setShowModal] = useState(false);
  const [loading, setLoading] = useState(false);
  const [user, setUser] = useState<User | null>(null);
  const [formData, setFormData] = useState({
    description: '',
    discount: '',
    expiresAt: ''
  });
  const [file, setFile] = useState<File | null>(null);

  // Monitora o estado de autenticação
  useEffect(() => {
    if (auth) {
      const unsubscribe = onAuthStateChanged(auth, (currentUser) => {
        setUser(currentUser);
      });
      return () => unsubscribe();
    }
  }, []);

  const handleCreatePromo = async () => {
    if (!formData.description || !file) {
      alert("⚠️ Preencha a descrição e escolha uma foto ou vídeo.");
      return;
    }

    if (!isFirebaseConfigured || !db || !storage || !auth) {
      alert("❌ Firebase não configurado corretamente.");
      return;
    }

    setLoading(true);
    try {
      // 1. Garante que o usuário está autenticado (Regra de escrita exige auth)
      if (!auth.currentUser) {
        console.log("Autenticando anonimamente para permitir a publicação...");
        await signInAnonymously(auth);
      }

      // 2. Upload do Arquivo para o Storage
