service firebase.storage {
  match /b/{bucket}/o {
    // Regras para a pasta de promoções
    match /promotions/{allPaths=**} {
      // Permite que qualquer usuário (mesmo não autenticado) visualize as imagens e vídeos
      allow read: if true;

      // Permite que qualquer usuário autenticado faça upload, atualize ou delete arquivos
      // Isso é necessário para que o MerchantDashboard (que usa login anônimo) funcione
      allow write: if request.auth != null;
    }
  }
}

