interface DiagItemProps {
  label: string;
  status: 'idle' | 'loading' | 'success' | 'error';
  icon: React.ReactNode;
}

const DiagItem: React.FC<DiagItemProps> = ({ label, status, icon }) => {
  const getStatusColor = () => {
    switch (status) {
      case 'success': return 'text-green-500 bg-green-50';
      case 'error': return 'text-rose-500 bg-rose-50';
      case 'loading': return 'text-amber-500 animate-pulse';
      default: return 'text-gray-300';
    }
  };

  return (
    <div className="flex items-center justify-between py-1 px-2 rounded-lg hover:bg-gray-50 transition-colors">
      <div className="flex items-center gap-2">
        <div className={`p-1.5 rounded-md ${getStatusColor()}`}>
          {icon}
        </div>
        <span className="text-[11px] font-bold text-gray-600 uppercase tracking-tighter">{label}</span>
      </div>
      {status === 'loading' ? (
        <Loader2 size={12} className="animate-spin text-amber-500" />
      ) : status === 'success' ? (
        <CheckCircle size={14} className="text-green-500" />
      ) : status === 'error' ? (
        <X size={14} className="text-rose-500" />
      ) : (
        <div className="w-3 h-3 rounded-full bg-gray-100" />
      )}
    </div>
  );
};

