import { useState, useEffect } from 'react';
import { collection, query, onSnapshot, orderBy } from 'firebase/firestore';
import { db, isFirebaseConfigured } from '../firebase';
import { Promotion } from '../types';
import { MOCK_PROMOTIONS } from '../constants';

export const usePromotions = () => {
  const [promotions, setPromotions] = useState<Promotion[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [isUsingMock, setIsUsingMock] = useState(false);

  useEffect(() => {
    // Se o Firebase não estiver configurado ou o db falhar, usamos MOCK
    if (!isFirebaseConfigured || !db) {
      console.warn("Firebase não configurado ou Firestore indisponível. Usando MOCK.");
      setPromotions(MOCK_PROMOTIONS);
      setIsUsingMock(true);
      setLoading(false);
      return;
    }

    let unsubscribe = () => {};

    try {
      const promosRef = collection(db, "promotions");
      const q = query(promosRef, orderBy("createdAt", "desc"));

      unsubscribe = onSnapshot(q, (querySnapshot) => {
        const promos: Promotion[] = [];
        querySnapshot.forEach((doc) => {
          const data = doc.data();
          promos.push({ 
            id: doc.id, 
            ...data,
            // Fallback para campos de data caso venham do Firestore
            expiresAt: data.expiresAt || 'Indeterminado'
          } as Promotion);
        });

        if (promos.length === 0) {
          setPromotions(MOCK_PROMOTIONS);
          setIsUsingMock(true);
        } else {
          setPromotions(promos);
          setIsUsingMock(false);
        }

        setLoading(false);
        setError(null);
      }, (err) => {
        console.error("Erro no Firestore Snapshot:", err);
        setError(err.message);
        setPromotions(MOCK_PROMOTIONS);
        setIsUsingMock(true);
        setLoading(false);
      });
    } catch (err: any) {
      console.error("Erro ao configurar listener:", err);
      setPromotions(MOCK_PROMOTIONS);
      setIsUsingMock(true);
      setLoading(false);
    }

    return () => unsubscribe();
  }, []);

  return { promotions, loading, error, isUsingMock };
};

