import React, { useState, useEffect } from 'react';
import { collection, addDoc, serverTimestamp, getDocs, limit, query } from 'firebase/firestore';
import { ref, uploadBytes, getDownloadURL } from 'firebase/storage';
import { signInAnonymously, onAuthStateChanged, User } from 'firebase/auth';
import { db, storage, auth, isFirebaseConfigured, app } from '../firebase';
import { Plus, BarChart2, MessageSquare, CheckCircle, Loader2, X, AlertTriangle, ShieldCheck, Activity, Globe, Database, Lock, HardDrive, Zap } from 'lucide-react';
import { MOCK_PROMOTIONS } from '../constants';

const MerchantDashboard: React.FC = () => {
  const [showModal, setShowModal] = useState(false);
  const [loading, setLoading] = useState(false);
  const [seeding, setSeeding] = useState(false);
  const [user, setUser] = useState<User | null>(null);
  const [diagOpen, setDiagOpen] = useState(false);
  const [diagStatus, setDiagStatus] = useState<{
    app: 'idle' | 'loading' | 'success' | 'error';
    auth: 'idle' | 'loading' | 'success' | 'error';
    firestore: 'idle' | 'loading' | 'success' | 'error';
    storage: 'idle' | 'loading' | 'success' | 'error';
  }>({ app: 'idle', auth: 'idle', firestore: 'idle', storage: 'idle' });

  const [formData, setFormData] = useState({
    description: '',
    discount: '',
    expiresAt: ''
  });
  const [file, setFile] = useState<File | null>(null);

  useEffect(() => {
    if (auth) {
      const unsubscribe = onAuthStateChanged(auth, (currentUser) => {
        setUser(currentUser);
      });
      return () => unsubscribe();
    }
  }, []);

  const runDiagnostics = async () => {
    setDiagOpen(true);
    setDiagStatus({ app: 'loading', auth: 'loading', firestore: 'loading', storage: 'loading' });

    setTimeout(() => {
      setDiagStatus(prev => ({ ...prev, app: app ? 'success' : 'error' }));
    }, 500);

    try {
      if (!auth) throw new Error();
      await signInAnonymously(auth);
      setDiagStatus(prev => ({ ...prev, auth: 'success' }));
    } catch (e) {
      setDiagStatus(prev => ({ ...prev, auth: 'error' }));
    }

    try {
      if (!db) throw new Error();
      const q = query(collection(db, "promotions"), limit(1));
      await getDocs(q);
      setDiagStatus(prev => ({ ...prev, firestore: 'success' }));
    } catch (e) {
      setDiagStatus(prev => ({ ...prev, firestore: 'error' }));
    }

    try {
      if (!storage) throw new Error();
      setDiagStatus(prev => ({ ...prev, storage: 'success' }));
    } catch (e) {
      setDiagStatus(prev => ({ ...prev, storage: 'error' }));
    }
  };

  const seedDatabase = async () => {
    if (!db || !auth) return;
    setSeeding(true);
    try {
      if (!auth.currentUser) await signInAnonymously(auth);

      const promosRef = collection(db, "promotions");
      for (const promo of MOCK_PROMOTIONS) {
        await addDoc(promosRef, {
          ...promo,
          createdAt: serverTimestamp(),
          storeId: auth.currentUser?.uid || 'system_seed'
        });
      }
      alert("✅ Banco de dados populado com sucesso! Volte ao Início para ver as promoções reais.");
    } catch (error: any) {
      alert("Erro ao popular: " + error.message);
    } finally {
      setSeeding(false);
    }
  };

  const handleCreatePromo = async () => {
    if (!formData.description || !file) {
      alert("⚠️ Preencha a descrição e escolha uma foto ou vídeo.");
      return;
    }

    if (!isFirebaseConfigured || !db || !storage || !auth) {
      alert("❌ Firebase não configurado corretamente.");
      return;
    }

    setLoading(true);
    try {
      if (!auth.currentUser) {
        await signInAnonymously(auth);
      }

      const fileExt = file.name.split('.').pop();
      const fileName = `promo_${Date.now()}.${fileExt}`;
      const storageRef = ref(storage, `promotions/${fileName}`);

      const snapshot = await uploadBytes(storageRef, file);
      const downloadUrl = await getDownloadURL(snapshot.ref);

      await addDoc(collection(db, "promotions"), {
        description: formData.description,
        discount: formData.discount || "Promoção",
        expiresAt: formData.expiresAt || "Indeterminado",
        imageUrl: downloadUrl,
        storeId: auth.currentUser?.uid || 'lojista_demo', 
        storeName: 'Minha Loja Parceira',
        storeLogo: 'https://images.unsplash.com/photo-1441986300917-64674bd600d8?w=100&h=100&fit=crop',
        likes: 0,
        saved: false,
        createdAt: serverTimestamp()
      });

      setShowModal(false);
      setFormData({ description: '', discount: '', expiresAt: '' });
      setFile(null);
      alert("🚀 Promoção publicada com sucesso!");
    } catch (error: any) {
      console.error("Erro na publicação:", error);
      alert(`Falha ao publicar: ${error.message}`);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="p-4 h-full bg-gray-50 overflow-y-auto pb-20">
      <div className="flex items-center justify-between mb-8">
        <div className="text-left">
          <h1 className="text-2xl font-bold text-gray-800">Painel do Lojista</h1>
          <div className="flex items-center gap-1.5 mt-1">
            {user ? (
              <span className="flex items-center gap-1 text-[10px] font-bold text-green-600 bg-green-50 px-2 py-0.5 rounded-full border border-green-100 uppercase">
                <ShieldCheck size={10} /> Conectado com Segurança
              </span>
            ) : (
              <p className="text-sm text-gray-500">Gerencie suas ofertas</p>
            )}
          </div>
        </div>
        <button 
          onClick={runDiagnostics}
          className="bg-white p-2.5 rounded-xl border border-gray-200 shadow-sm text-gray-400 hover:text-indigo-600 transition-colors"
        >
          <Activity size={20} />
        </button>
      </div>

      <div className="grid grid-cols-2 gap-4 mb-8 text-left">
        <div className="bg-white p-4 rounded-2xl border border-gray-100 shadow-sm">
          <p className="text-[10px] text-gray-500 uppercase font-bold tracking-widest mb-1">Visualizações</p>
          <p className="text-xl font-black text-indigo-600">--</p>
        </div>
        <div className="bg-white p-4 rounded-2xl border border-gray-100 shadow-sm">
          <p className="text-[10px] text-gray-500 uppercase font-bold tracking-widest mb-1">Cliques</p>
          <p className="text-xl font-black text-indigo-600">--</p>
        </div>
      </div>

      <div className="flex flex-col gap-3 mb-8">
        <button 
          onClick={() => setShowModal(true)}
          className="w-full bg-indigo-600 hover:bg-indigo-700 text-white font-bold py-4 rounded-2xl flex items-center justify-center gap-2 shadow-lg shadow-indigo-200 transition-all"
        >
          <Plus size={24} />
          NOVA PROMOÇÃO
        </button>

        <button 
          onClick={seedDatabase}
          disabled={seeding}
          className="w-full bg-white border-2 border-dashed border-indigo-200 text-indigo-600 font-bold py-3 rounded-2xl flex items-center justify-center gap-2 hover:bg-indigo-50 transition-all"
        >
          {seeding ? <Loader2 className="animate-spin" size={20} /> : <Zap size={20} />}
          {seeding ? 'POPULANDO...' : 'POPULAR BANCO COM TESTES'}
        </button>
      </div>

      {diagOpen && (
        <div className="mb-8 p-5 bg-white rounded-3xl border border-gray-100 shadow-xl animate-fade-in text-left">
          <div className="flex items-center justify-between mb-4">
            <h3 className="text-xs font-black text-gray-400 uppercase tracking-widest">Teste de Conectividade</h3>
            <button onClick={() => setDiagOpen(false)}><X size={16} className="text-gray-300" /></button>
          </div>
          <div className="space-y-3">
            <DiagItem label="Firebase Core" status={diagStatus.app} icon={<Globe size={14} />} />
            <DiagItem label="Autenticação" status={diagStatus.auth} icon={<Lock size={14} />} />
            <DiagItem label="Firestore DB" status={diagStatus.firestore} icon={<Database size={14} />} />
            <DiagItem label="Storage Cloud" status={diagStatus.storage} icon={<HardDrive size={14} />} />
          </div>
