          <button className="w-full flex items-center gap-4 p-4 hover:bg-gray-50 transition-colors text-left">
            <div className="bg-purple-100 p-2 rounded-lg text-purple-600"><MessageSquare size={20} /></div>
            <span className="font-semibold text-gray-700 flex-1 text-sm">Falar com Suporte</span>
          </button>
        </div>
      </div>

      {showModal && (
        <div className="fixed inset-0 z-[100] bg-black/80 flex items-end sm:items-center justify-center p-4 backdrop-blur-md animate-fade-in">
