// Lógica de Banco de Dados Local (LocalStorage)
const LOCAL_STORAGE_KEY = 'descontai_local_promos';

export const getLocalPromotions = (): Promotion[] => {
  const stored = localStorage.getItem(LOCAL_STORAGE_KEY);
  if (!stored) return [];
  try {
    return JSON.parse(stored);
  } catch {
    return [];
  }
};

export const saveLocalPromotion = (promo: Promotion) => {
  const current = getLocalPromotions();
  const updated = [promo, ...current];
  localStorage.setItem(LOCAL_STORAGE_KEY, JSON.stringify(updated));
  // Disparar evento para atualizar hooks em outras telas
  window.dispatchEvent(new Event('storage_update'));
};

export const clearLocalPromotions = () => {
  localStorage.removeItem(LOCAL_STORAGE_KEY);
  window.dispatchEvent(new Event('storage_update'));
};

import { useState, useEffect } from 'react';
import { Promotion } from '../types';
import { MOCK_PROMOTIONS, getLocalPromotions } from '../constants';

export const usePromotions = () => {
  const [promotions, setPromotions] = useState<Promotion[]>([]);
  const [loading, setLoading] = useState(true);

  const loadAll = () => {
    setLoading(true);
    const locals = getLocalPromotions();
    // Prioriza locais e depois mock
    setPromotions([...locals, ...MOCK_PROMOTIONS]);
    setLoading(false);
  };

  useEffect(() => {
    loadAll();

    // Listener para quando o usuário adicionar algo em outra tela (Dashboard)
    const handleUpdate = () => loadAll();
    window.addEventListener('storage_update', handleUpdate);
    return () => window.removeEventListener('storage_update', handleUpdate);
  }, []);

  return { 
    promotions, 
    loading, 
    error: null, 
    isUsingMock: getLocalPromotions().length === 0 
  };
};

