// Lógica de Banco de Dados Local (LocalStorage)
const LOCAL_STORAGE_KEY = 'descontai_local_promos';
const MERCHANT_PROFILE_KEY = 'descontai_local_merchant';

export interface MerchantProfile {
  name: string;
  logo: string;
}

export const getLocalPromotions = (): Promotion[] => {
  const stored = localStorage.getItem(LOCAL_STORAGE_KEY);
  if (!stored) return [];
  try {
    return JSON.parse(stored);
  } catch {
    return [];
  }
};

export const saveLocalPromotion = (promo: Promotion) => {
  const current = getLocalPromotions();
  const updated = [promo, ...current];
  localStorage.setItem(LOCAL_STORAGE_KEY, JSON.stringify(updated));
  window.dispatchEvent(new Event('storage_update'));
};

export const clearLocalPromotions = () => {
  localStorage.removeItem(LOCAL_STORAGE_KEY);
  window.dispatchEvent(new Event('storage_update'));
};

export const getMerchantProfile = (): MerchantProfile => {
  const stored = localStorage.getItem(MERCHANT_PROFILE_KEY);
  if (!stored) return { name: 'Minha Loja', logo: 'https://images.unsplash.com/photo-1441986300917-64674bd600d8?w=100&h=100&fit=crop' };
  try {
    return JSON.parse(stored);
  } catch {
    return { name: 'Minha Loja', logo: 'https://images.unsplash.com/photo-1441986300917-64674bd600d8?w=100&h=100&fit=crop' };
  }
};

export const saveMerchantProfile = (profile: MerchantProfile) => {
  localStorage.setItem(MERCHANT_PROFILE_KEY, JSON.stringify(profile));
  window.dispatchEvent(new Event('merchant_update'));
};

import React, { useState, useEffect } from 'react';
import { Plus, BarChart2, MessageSquare, CheckCircle, Loader2, X, Trash2, Database, ShieldCheck, Zap, Store, Camera, Edit3 } from 'lucide-react';
import { saveLocalPromotion, clearLocalPromotions, getLocalPromotions, getMerchantProfile, saveMerchantProfile, MerchantProfile } from '../constants';
import { Promotion } from '../types';

const MerchantDashboard: React.FC = () => {
  const [showModal, setShowModal] = useState(false);
  const [showProfileModal, setShowProfileModal] = useState(false);
  const [loading, setLoading] = useState(false);
  const [localCount, setLocalCount] = useState(getLocalPromotions().length);
  const [merchant, setMerchant] = useState<MerchantProfile>(getMerchantProfile());

  const [formData, setFormData] = useState({
    description: '',
    discount: '',
    expiresAt: ''
  });
  const [file, setFile] = useState<File | null>(null);

  // Profile Form Data
  const [profileData, setProfileData] = useState<MerchantProfile>(merchant);

  useEffect(() => {
    const handleUpdate = () => {
      setLocalCount(getLocalPromotions().length);
      setMerchant(getMerchantProfile());
    };
    window.addEventListener('storage_update', handleUpdate);
    window.addEventListener('merchant_update', handleUpdate);
    return () => {
      window.removeEventListener('storage_update', handleUpdate);
      window.removeEventListener('merchant_update', handleUpdate);
    };
  }, []);

  const handleCreatePromo = async () => {
    if (!formData.description || !file) {
      alert("⚠️ Preencha a descrição e escolha uma foto.");
      return;
    }

    setLoading(true);

    const reader = new FileReader();
    reader.onloadend = () => {
      const base64Data = reader.result as string;

      let formattedDate = "31/12/2025";
      if (formData.expiresAt) {
        const [year, month, day] = formData.expiresAt.split('-');
        formattedDate = `${day}/${month}/${year}`;
      }

      const newPromo: Promotion = {
        id: `local_${Date.now()}`,
        storeId: 'lojista_local',
        storeName: merchant.name,
        storeLogo: merchant.logo,
        imageUrl: base64Data,
        description: formData.description,
        discount: formData.discount || "Oferta Especial",
        expiresAt: formattedDate,
        likes: 0,
        saved: false
      };

      saveLocalPromotion(newPromo);
      setLoading(false);
      setShowModal(false);
      setFormData({ description: '', discount: '', expiresAt: '' });
      setFile(null);
    };
    reader.readAsDataURL(file);
  };

  const handleUpdateProfile = () => {
    if (!profileData.name) {
      alert("O nome da empresa é obrigatório.");
      return;
    }
    saveMerchantProfile(profileData);
    setShowProfileModal(false);
    alert("Perfil atualizado com sucesso!");
  };

  const handleLogoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const logoFile = e.target.files?.[0];
    if (logoFile) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setProfileData({ ...profileData, logo: reader.result as string });
      };
      reader.readAsDataURL(logoFile);
    }
  };

  const handleClear = () => {
    if (confirm("Deseja apagar todas as promoções criadas localmente?")) {
      clearLocalPromotions();
    }
  };

  return (
    <div className="p-4 h-full bg-gray-50 overflow-y-auto pb-20">
      <div className="flex items-center justify-between mb-8">
        <div className="text-left">
          <h1 className="text-2xl font-bold text-gray-800">Painel do Lojista</h1>
          <div className="flex items-center gap-1.5 mt-1">
             <span className="flex items-center gap-1 text-[10px] font-bold text-indigo-600 bg-indigo-50 px-2 py-0.5 rounded-full border border-indigo-100 uppercase">
                <ShieldCheck size={10} /> Modo Local Ativado
              </span>
          </div>
        </div>
        <button 
          onClick={handleClear}
          title="Limpar Banco Local"
          className="bg-white p-2.5 rounded-xl border border-gray-200 shadow-sm text-gray-400 hover:text-red-600 transition-colors"
        >
          <Trash2 size={20} />
        </button>
      </div>

      {/* Merchant Profile Card */}
      <div className="bg-white p-4 rounded-3xl border border-gray-100 shadow-sm mb-6 flex items-center gap-4 relative overflow-hidden">
        <div className="absolute top-0 right-0 p-2">
          <button 
            onClick={() => {
              setProfileData(merchant);
              setShowProfileModal(true);
            }}
            className="p-2 text-indigo-600 hover:bg-indigo-50 rounded-full transition-colors"
          >
            <Edit3 size={18} />
          </button>
        </div>
        <img 
          src={merchant.logo} 
          alt={merchant.name} 
          className="w-16 h-16 rounded-2xl object-cover border-2 border-indigo-50 shadow-sm"
        />
        <div className="text-left">
          <h2 className="font-black text-gray-800 text-lg leading-tight">{merchant.name}</h2>
          <p className="text-xs text-gray-400 font-bold uppercase tracking-widest mt-0.5">Perfil Ativo</p>
        </div>
      </div>

      <div className="grid grid-cols-2 gap-4 mb-8 text-left">
        <div className="bg-white p-4 rounded-2xl border border-gray-100 shadow-sm">
          <p className="text-[10px] text-gray-500 uppercase font-bold tracking-widest mb-1">Ofertas Ativas</p>
          <p className="text-xl font-black text-indigo-600">{localCount}</p>
        </div>
        <div className="bg-white p-4 rounded-2xl border border-gray-100 shadow-sm">
          <p className="text-[10px] text-gray-500 uppercase font-bold tracking-widest mb-1">Status</p>
          <p className="text-xl font-black text-green-600">Conectado</p>
        </div>
      </div>

      <div className="flex flex-col gap-3 mb-8">
        <button 
          onClick={() => setShowModal(true)}
          className="w-full bg-indigo-600 hover:bg-indigo-700 text-white font-bold py-4 rounded-2xl flex items-center justify-center gap-2 shadow-lg shadow-indigo-200 transition-all active:scale-95"
        >
          <Plus size={24} />
          CRIAR NOVA OFERTA
        </button>

        <div className="p-4 bg-amber-50 border border-amber-100 rounded-2xl flex items-start gap-3">
          <Database size={20} className="text-amber-600 shrink-0 mt-0.5" />
          <p className="text-[11px] text-amber-800 leading-tight text-left">
            <strong>Dica:</strong> Mantenha seu perfil atualizado. O logo e o nome acima aparecerão no topo de cada oferta para seus clientes.
          </p>
        </div>
      </div>

      {/* Tools Section */}
      <div className="space-y-4">
        <h2 className="text-xs font-bold text-gray-500 uppercase tracking-widest text-left">Configurações</h2>
        <div className="bg-white rounded-2xl border border-gray-100 shadow-sm overflow-hidden">
          <button 
            onClick={() => setShowProfileModal(true)}
            className="w-full flex items-center gap-4 p-4 hover:bg-gray-50 border-b border-gray-50 transition-colors text-left"
          >
            <div className="bg-indigo-100 p-2 rounded-lg text-indigo-600"><Store size={20} /></div>
            <span className="font-semibold text-gray-700 flex-1 text-sm">Dados da Empresa</span>
          </button>
          <button className="w-full flex items-center gap-4 p-4 hover:bg-gray-50 border-b border-gray-50 transition-colors text-left">
            <div className="bg-blue-100 p-2 rounded-lg text-blue-600"><BarChart2 size={20} /></div>
            <span className="font-semibold text-gray-700 flex-1 text-sm">Desempenho das Vendas</span>
          </button>
          <button className="w-full flex items-center gap-4 p-4 hover:bg-gray-50 transition-colors text-left">
            <div className="bg-purple-100 p-2 rounded-lg text-purple-600"><MessageSquare size={20} /></div>
            <span className="font-semibold text-gray-700 flex-1 text-sm">Suporte</span>
          </button>
        </div>
      </div>

      {/* Modal: Editar Perfil */}
      {showProfileModal && (
        <div className="fixed inset-0 z-[110] bg-black/80 flex items-end sm:items-center justify-center p-4 backdrop-blur-md animate-fade-in">
          <div className="bg-white w-full max-w-sm rounded-t-3xl sm:rounded-3xl p-6 relative shadow-2xl overflow-y-auto">
            <button onClick={() => setShowProfileModal(false)} className="absolute top-4 right-4 text-gray-400 p-2">
              <X size={24} />
