            <div className="text-left mb-6">
              <h3 className="text-xl font-bold mb-1">Perfil da Loja</h3>
              <p className="text-sm text-gray-500">Identifique sua marca no Descontaí.</p>
            </div>

            <div className="space-y-6 text-left mb-8">
              <div className="flex flex-col items-center">
                <div className="relative group">
                  <img 
                    src={profileData.logo} 
                    className="w-24 h-24 rounded-3xl object-cover border-4 border-indigo-50 shadow-md" 
                    alt="Logo Preview" 
                  />
                  <label className="absolute inset-0 flex items-center justify-center bg-black/40 rounded-3xl cursor-pointer opacity-0 group-hover:opacity-100 transition-opacity">
                    <Camera size={24} className="text-white" />
                    <input type="file" accept="image/*" className="hidden" onChange={handleLogoUpload} />
                  </label>
                </div>
                <span className="text-[10px] font-black text-indigo-600 uppercase mt-2 tracking-widest">Alterar Logo</span>
              </div>

              <div>
                <label className="text-xs font-bold text-gray-400 uppercase tracking-wider">Nome da Empresa</label>
                <input 
                  value={profileData.name}
                  onChange={(e) => setProfileData({...profileData, name: e.target.value})}
                  type="text" 
                  className="w-full bg-gray-50 border border-gray-200 rounded-xl p-3 text-sm focus:ring-2 focus:ring-indigo-500 outline-none mt-1"
