const MerchantDashboard: React.FC = () => {
  const [showModal, setShowModal] = useState(false);
  const [showProfileModal, setShowProfileModal] = useState(false);
  const [loading, setLoading] = useState(false);
  const [localCount, setLocalCount] = useState(getLocalPromotions().length);
  const [merchant, setMerchant] = useState<MerchantProfile>(getMerchantProfile());

  const [formData, setFormData] = useState({
    description: '',
    discount: '',
    expiresAt: ''
  });
  const [file, setFile] = useState<File | null>(null);

  // Profile Form Data
  const [profileData, setProfileData] = useState<MerchantProfile>(merchant);

  useEffect(() => {
    const handleUpdate = () => {
      setLocalCount(getLocalPromotions().length);
      setMerchant(getMerchantProfile());
    };
    window.addEventListener('storage_update', handleUpdate);
    window.addEventListener('merchant_update', handleUpdate);
    return () => {
      window.removeEventListener('storage_update', handleUpdate);
      window.removeEventListener('merchant_update', handleUpdate);
    };
  }, []);

  const handleCreatePromo = async () => {
    if (!formData.description || !file) {
      alert("⚠️ Preencha a descrição e escolha uma foto.");
      return;
    }

    setLoading(true);

    const reader = new FileReader();
    reader.onloadend = () => {
      const base64Data = reader.result as string;

      let formattedDate = "31/12/2025";
      if (formData.expiresAt) {
        const [year, month, day] = formData.expiresAt.split('-');
        formattedDate = `${day}/${month}/${year}`;
      }

      const newPromo: Promotion = {
        id: `local_${Date.now()}`,
        storeId: 'lojista_local',
        storeName: merchant.name,
        storeLogo: merchant.logo,
        imageUrl: base64Data,
        description: formData.description,
        discount: formData.discount || "Oferta Especial",
        expiresAt: formattedDate,
        likes: 0,
        saved: false
      };

      saveLocalPromotion(newPromo);
      setLoading(false);
      setShowModal(false);
      setFormData({ description: '', discount: '', expiresAt: '' });
      setFile(null);
    };
    reader.readAsDataURL(file);
  };

  const handleUpdateProfile = () => {
    if (!profileData.name) {
      alert("O nome da empresa é obrigatório.");
      return;
    }
    saveMerchantProfile(profileData);
    setShowProfileModal(false);
    alert("Perfil atualizado com sucesso!");
  };

  const handleLogoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const logoFile = e.target.files?.[0];
    if (logoFile) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setProfileData({ ...profileData, logo: reader.result as string });
      };
      reader.readAsDataURL(logoFile);
    }
  };

  const handleClear = () => {
    if (confirm("Deseja apagar todas as promoções criadas localmente?")) {
      clearLocalPromotions();
    }
  };

  const handleLogout = () => {
    if (confirm("Deseja sair do painel do lojista?")) {
      setAuthUser(null);
    }
  };

  return (
    <div className="p-4 h-full bg-gray-50 overflow-y-auto pb-20">
      <div className="flex items-center justify-between mb-8">
        <div className="text-left">
          <h1 className="text-2xl font-bold text-gray-800">Painel do Lojista</h1>
          <div className="flex items-center gap-1.5 mt-1">
             <span className="flex items-center gap-1 text-[10px] font-bold text-indigo-600 bg-indigo-50 px-2 py-0.5 rounded-full border border-indigo-100 uppercase">
                <ShieldCheck size={10} /> Modo Local Ativado
