        <div className="flex items-center gap-2">
          <button 
            onClick={handleClear}
            title="Limpar Banco Local"
            className="bg-white p-2.5 rounded-xl border border-gray-200 shadow-sm text-gray-400 hover:text-red-600 transition-colors"
