            <Trash2 size={20} />
          </button>
          <button 
            onClick={handleLogout}
            title="Sair da Conta"
            className="bg-white p-2.5 rounded-xl border border-gray-100 shadow-sm text-gray-400 hover:text-rose-600 transition-colors"
          >
            <LogOut size={20} />
          </button>
        </div>
      </div>

      {/* Merchant Profile Card */}
      <div className="bg-white p-4 rounded-3xl border border-gray-100 shadow-sm mb-6 flex items-center gap-4 relative overflow-hidden">
        <div className="absolute top-0 right-0 p-2">
          <button 
            onClick={() => {
              setProfileData(merchant);
              setShowProfileModal(true);
            }}
            className="p-2 text-indigo-600 hover:bg-indigo-50 rounded-full transition-colors"
          >
            <Edit3 size={18} />
          </button>
        </div>
        <img 
          src={merchant.logo} 
          alt={merchant.name} 
          className="w-16 h-16 rounded-2xl object-cover border-2 border-indigo-50 shadow-sm"
        />
        <div className="text-left">
          <h2 className="font-black text-gray-800 text-lg leading-tight">{merchant.name}</h2>
          <p className="text-xs text-gray-400 font-bold uppercase tracking-widest mt-0.5">Perfil Ativo</p>
        </div>
