import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import FeedScreen from './components/FeedScreen';
import ExploreScreen from './components/ExploreScreen';
import MerchantDashboard from './components/MerchantDashboard';
import ProfileScreen from './components/ProfileScreen';
import AuthScreen from './components/AuthScreen';
import AdminDashboard from './components/AdminDashboard';
import { ViewType, AuthUser } from './types';
import { getAuthUser } from './constants';

const App: React.FC = () => {
  const [user, setUser] = useState<AuthUser | null>(getAuthUser());
  const [currentView, setCurrentView] = useState<ViewType>('AUTH');

  useEffect(() => {
    const handleAuthChange = () => {
      const newUser = getAuthUser();
      setUser(newUser);

      if (newUser) {
        // Define a visão inicial baseada no cargo após o login
        if (newUser.role === 'ADMIN') setCurrentView('ADMIN_STORES');
        else if (newUser.role === 'MERCHANT') setCurrentView('MERCHANT');
        else setCurrentView('FEED');
      } else {
        // Força a visão de autenticação ao deslogar
        setCurrentView('AUTH');
      }
    };

    // Inicializa o estado
    handleAuthChange();

    window.addEventListener('auth_change', handleAuthChange);
    return () => window.removeEventListener('auth_change', handleAuthChange);
  }, []);

  const renderContent = () => {
    if (!user) return <AuthScreen />;

    switch (currentView) {
      case 'FEED': return <FeedScreen />;
      case 'EXPLORE': return <ExploreScreen />;
      case 'MERCHANT': return <MerchantDashboard />;
      case 'PROFILE': return <ProfileScreen />;
      case 'ADMIN_STORES': return <AdminDashboard />;
      default: return <FeedScreen />;
    }
  };

  return (
    <div className="min-h-screen bg-neutral-950 flex justify-center items-center overflow-hidden">
      {/* Background Orbs para Desktop */}
      <div className="fixed inset-0 pointer-events-none opacity-20 overflow-hidden hidden sm:block">
        <div className="absolute top-[-10%] left-[-10%] w-[40%] h-[40%] bg-indigo-600 blur-[120px] rounded-full" />
        <div className="absolute bottom-[-10%] right-[-10%] w-[40%] h-[40%] bg-rose-600 blur-[120px] rounded-full" />
      </div>

      <Layout activeView={currentView} onViewChange={setCurrentView} user={user}>
        <div className="h-full w-full animate-fade-in">
          {renderContent()}
        </div>
      </Layout>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Plus, BarChart2, MessageSquare, CheckCircle, Loader2, X, Trash2, Database, ShieldCheck, Zap, Store, Camera, Edit3, LogOut } from 'lucide-react';
import { saveLocalPromotion, clearLocalPromotions, getLocalPromotions, getMerchantProfile, saveMerchantProfile, MerchantProfile, setAuthUser } from '../constants';
import { Promotion } from '../types';

const MerchantDashboard: React.FC = () => {
  const [showModal, setShowModal] = useState(false);
  const [showProfileModal, setShowProfileModal] = useState(false);
  const [loading, setLoading] = useState(false);
  const [localCount, setLocalCount] = useState(getLocalPromotions().length);
  const [merchant, setMerchant] = useState<MerchantProfile>(getMerchantProfile());

  const [formData, setFormData] = useState({
    description: '',
    discount: '',
    expiresAt: ''
  });
  const [file, setFile] = useState<File | null>(null);
  const [profileData, setProfileData] = useState<MerchantProfile>(merchant);

  useEffect(() => {
    const handleUpdate = () => {
      setLocalCount(getLocalPromotions().length);
      setMerchant(getMerchantProfile());
    };
    window.addEventListener('storage_update', handleUpdate);
    window.addEventListener('merchant_update', handleUpdate);
    return () => {
      window.removeEventListener('storage_update', handleUpdate);
      window.removeEventListener('merchant_update', handleUpdate);
    };
  }, []);

  const handleCreatePromo = async () => {
    if (!formData.description || !file) {
      alert("⚠️ Preencha a descrição e escolha uma foto.");
      return;
    }
    setLoading(true);
    const reader = new FileReader();
    reader.onloadend = () => {
      const base64Data = reader.result as string;
      let formattedDate = "31/12/2025";
      if (formData.expiresAt) {
        const [year, month, day] = formData.expiresAt.split('-');
        formattedDate = `${day}/${month}/${year}`;
      }
      const newPromo: Promotion = {
        id: `local_${Date.now()}`,
        storeId: 'lojista_local',
        storeName: merchant.name,
        storeLogo: merchant.logo,
        imageUrl: base64Data,
        description: formData.description,
        discount: formData.discount || "Oferta Especial",
        expiresAt: formattedDate,
        likes: 0,
        saved: false
      };
      saveLocalPromotion(newPromo);
