import React, { useState, useEffect } from 'react';
import { Plus, BarChart2, MessageSquare, CheckCircle, Loader2, X, Trash2, Database, ShieldCheck, Zap, Store, Camera, Edit3, LogOut } from 'lucide-react';
import { saveLocalPromotion, clearLocalPromotions, getLocalPromotions, getMerchantProfile, saveMerchantProfile, MerchantProfile, setAuthUser } from '../constants';
import { Promotion } from '../types';

const MerchantDashboard: React.FC = () => {
  const [showModal, setShowModal] = useState(false);
  const [showProfileModal, setShowProfileModal] = useState(false);
  const [loading, setLoading] = useState(false);
  const [localCount, setLocalCount] = useState(getLocalPromotions().length);
  const [merchant, setMerchant] = useState<MerchantProfile>(getMerchantProfile());

  const [formData, setFormData] = useState({
    description: '',
    discount: '',
    expiresAt: ''
  });
  const [file, setFile] = useState<File | null>(null);
  const [profileData, setProfileData] = useState<MerchantProfile>(merchant);

  useEffect(() => {
    const handleUpdate = () => {
      setLocalCount(getLocalPromotions().length);
      setMerchant(getMerchantProfile());
    };
    window.addEventListener('storage_update', handleUpdate);
    window.addEventListener('merchant_update', handleUpdate);
    return () => {
      window.removeEventListener('storage_update', handleUpdate);
      window.removeEventListener('merchant_update', handleUpdate);
    };
  }, []);

  const handleCreatePromo = async () => {
    if (!formData.description || !file) {
      alert("⚠️ Preencha a descrição e escolha uma foto.");
      return;
    }
    setLoading(true);
    const reader = new FileReader();
    reader.onloadend = () => {
      const base64Data = reader.result as string;
      let formattedDate = "31/12/2025";
      if (formData.expiresAt) {
        const [year, month, day] = formData.expiresAt.split('-');
        formattedDate = `${day}/${month}/${year}`;
      }
      const newPromo: Promotion = {
        id: `local_${Date.now()}`,
        storeId: 'lojista_local',
        storeName: merchant.name,
        storeLogo: merchant.logo,
        imageUrl: base64Data,
        description: formData.description,
        discount: formData.discount || "Oferta Especial",
        expiresAt: formattedDate,
        likes: 0,
        saved: false
      };
      saveLocalPromotion(newPromo);
      setLoading(false);
      setShowModal(false);
      setFormData({ description: '', discount: '', expiresAt: '' });
      setFile(null);
    };
    reader.readAsDataURL(file);
  };

  const handleUpdateProfile = () => {
    if (!profileData.name) {
      alert("O nome da empresa é obrigatório.");
      return;
    }
    saveMerchantProfile(profileData);
    setShowProfileModal(false);
  };

  const handleLogoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const logoFile = e.target.files?.[0];
    if (logoFile) {
      const reader = new FileReader();
      reader.onloadend = () => setProfileData({ ...profileData, logo: reader.result as string });
      reader.readAsDataURL(logoFile);
    }
  };

  const handleClear = () => {
    if (confirm("Deseja apagar todas as promoções criadas localmente?")) {
      clearLocalPromotions();
    }
  };

  const handleLogout = () => {
    if (confirm("Deseja realmente sair da sua conta de lojista?")) {
      setAuthUser(null);
    }
  };

  return (
    <div className="p-4 h-full bg-gray-50 overflow-y-auto pb-20 text-left">
      <div className="flex items-center justify-between mb-8">
        <div>
          <h1 className="text-2xl font-bold text-gray-800">Painel do Lojista</h1>
          <div className="flex items-center gap-1.5 mt-1">
             <span className="flex items-center gap-1 text-[10px] font-bold text-indigo-600 bg-indigo-50 px-2 py-0.5 rounded-full border border-indigo-100 uppercase">
                <ShieldCheck size={10} /> Modo Local Ativado
              </span>
          </div>
        </div>
        <div className="flex items-center gap-2">
          <button 
            onClick={handleClear}
            className="bg-white p-2.5 rounded-xl border border-gray-200 shadow-sm text-gray-400 hover:text-red-600 transition-colors"
            title="Limpar Local"
          >
            <Trash2 size={20} />
          </button>
          <button 
            onClick={handleLogout}
            className="bg-rose-600 p-2.5 rounded-xl border border-rose-700 shadow-lg text-white hover:bg-rose-700 transition-all active:scale-90"
            title="Sair da Conta"
          >
            <LogOut size={20} />
          </button>
        </div>
      </div>

      {/* Perfil Card */}
      <div className="bg-white p-4 rounded-3xl border border-gray-100 shadow-sm mb-6 flex items-center gap-4 relative">
        <button 
          onClick={() => { setProfileData(merchant); setShowProfileModal(true); }}
          className="absolute top-4 right-4 p-2 text-indigo-600 hover:bg-indigo-50 rounded-full transition-colors"
        >
          <Edit3 size={18} />
        </button>
        <img src={merchant.logo} className="w-16 h-16 rounded-2xl object-cover border-2 border-indigo-50 shadow-sm" />
        <div>
          <h2 className="font-black text-gray-800 text-lg leading-tight">{merchant.name}</h2>
          <p className="text-xs text-gray-400 font-bold uppercase tracking-widest mt-0.5">Lojista Parceiro</p>
        </div>
      </div>

      <div className="grid grid-cols-2 gap-4 mb-8">
