import React, { useState, useEffect } from 'react';
import { Plus, CheckCircle, Loader2, X, Trash2, ShieldCheck, Zap, Camera, Edit3, LogOut, Film, Image as ImageIcon, Calendar, Percent, Trash } from 'lucide-react';
import { saveLocalPromotion, clearLocalPromotions, getLocalPromotions, getMerchantProfile, saveMerchantProfile, MerchantProfile, setAuthUser } from '../constants';
import { Promotion } from '../types';

const MerchantDashboard: React.FC = () => {
  const [showModal, setShowModal] = useState(false);
  const [showProfileModal, setShowProfileModal] = useState(false);
  const [loading, setLoading] = useState(false);
  const [localPromos, setLocalPromos] = useState<Promotion[]>(getLocalPromotions());
  const [merchant, setMerchant] = useState<MerchantProfile>(getMerchantProfile());

  const [formData, setFormData] = useState({
    description: '',
    discount: '',
    expiresAt: ''
  });

  const [mediaFile, setMediaFile] = useState<File | null>(null);
  const [mediaPreview, setMediaPreview] = useState<string | null>(null);
  const [mediaType, setMediaType] = useState<'IMAGE' | 'VIDEO' | null>(null);
  const [profileData, setProfileData] = useState<MerchantProfile>(merchant);

  useEffect(() => {
    const handleUpdate = () => {
      setLocalPromos(getLocalPromotions());
      setMerchant(getMerchantProfile());
    };
    window.addEventListener('storage_update', handleUpdate);
    window.addEventListener('merchant_update', handleUpdate);
    return () => {
      window.removeEventListener('storage_update', handleUpdate);
      window.removeEventListener('merchant_update', handleUpdate);
    };
  }, []);

  const handleMediaChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setMediaFile(file);
      const isVideo = file.type.startsWith('video/');
      setMediaType(isVideo ? 'VIDEO' : 'IMAGE');

      const reader = new FileReader();
      reader.onloadend = () => {
        setMediaPreview(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleCreatePromo = async () => {
    if (!formData.description || !mediaPreview || !formData.discount || !formData.expiresAt) {
      alert("⚠️ Por favor, preencha todos os campos e adicione uma imagem ou vídeo.");
      return;
    }

    setLoading(true);

    // Formata a data de YYYY-MM-DD para DD/MM/YYYY
    const [year, month, day] = formData.expiresAt.split('-');
    const formattedDate = `${day}/${month}/${year}`;

    const newPromo: Promotion = {
      id: `local_${Date.now()}`,
      storeId: 'lojista_local',
      storeName: merchant.name,
      storeLogo: merchant.logo,
      imageUrl: mediaType === 'IMAGE' ? mediaPreview : '', // Usamos imageUrl como poster se for vídeo
      videoUrl: mediaType === 'VIDEO' ? mediaPreview : undefined,
      description: formData.description,
      discount: formData.discount.includes('%') ? formData.discount : `${formData.discount}% OFF`,
      expiresAt: formattedDate,
      likes: 0,
      saved: false
    };

    saveLocalPromotion(newPromo);

    // Reset form
    setLoading(false);
    setShowModal(false);
    setFormData({ description: '', discount: '', expiresAt: '' });
    setMediaFile(null);
    setMediaPreview(null);
    setMediaType(null);
  };

  const handleUpdateProfile = () => {
    if (!profileData.name) {
      alert("O nome da empresa é obrigatório.");
      return;
    }
    saveMerchantProfile(profileData);
    setShowProfileModal(false);
  };

  const handleLogoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const logoFile = e.target.files?.[0];
    if (logoFile) {
      const reader = new FileReader();
      reader.onloadend = () => setProfileData({ ...profileData, logo: reader.result as string });
      reader.readAsDataURL(logoFile);
    }
  };

  const handleClear = () => {
    if (confirm("Deseja apagar todas as suas promoções? Isso removerá as ofertas do feed público.")) {
      clearLocalPromotions();
    }
  };

  const handleLogout = () => {
    if (confirm("Deseja realmente sair da sua conta de lojista?")) {
      setAuthUser(null);
    }
  };

  return (
    <div className="p-4 h-full bg-gray-50 overflow-y-auto pb-24 text-left">
      {/* Header */}
      <div className="flex items-center justify-between mb-8">
        <div>
          <h1 className="text-2xl font-black text-gray-900 tracking-tighter italic">DASHBOARD</h1>
          <div className="flex items-center gap-1.5 mt-1">
             <span className="flex items-center gap-1 text-[10px] font-bold text-indigo-600 bg-indigo-50 px-2 py-0.5 rounded-full border border-indigo-100 uppercase tracking-widest">
                <ShieldCheck size={10} /> Conta Verificada
              </span>
          </div>
        </div>
        <div className="flex items-center gap-2">
          <button 
            onClick={handleClear}
            className="bg-white p-3 rounded-2xl border border-gray-200 shadow-sm text-gray-400 hover:text-red-600 transition-colors"
            title="Limpar Ofertas"
          >
            <Trash size={20} />
          </button>
          <button 
            onClick={handleLogout}
            className="bg-rose-600 p-3 rounded-2xl shadow-lg shadow-rose-100 text-white hover:bg-rose-700 transition-all active:scale-90"
            title="Sair"
          >
            <LogOut size={20} />
          </button>
        </div>
      </div>

      {/* Perfil Card */}
      <div className="bg-white p-5 rounded-[32px] border border-gray-100 shadow-sm mb-6 flex items-center gap-4 relative overflow-hidden">
        <div className="absolute top-0 right-0 w-24 h-24 bg-indigo-50 rounded-full -mr-12 -mt-12 opacity-50" />
        <button 
          onClick={() => { setProfileData(merchant); setShowProfileModal(true); }}
          className="absolute top-4 right-4 p-2 text-indigo-600 hover:bg-indigo-50 rounded-full transition-colors z-10"
        >
          <Edit3 size={18} />
        </button>
        <img src={merchant.logo} className="w-16 h-16 rounded-2xl object-cover border-2 border-indigo-100 shadow-sm z-10" />
        <div className="z-10">
          <h2 className="font-black text-gray-900 text-lg leading-tight">{merchant.name}</h2>
          <p className="text-[10px] text-gray-400 font-bold uppercase tracking-[0.2em] mt-1">Lojista Parceiro</p>
        </div>
      </div>

      {/* Stats e Botão de Ação */}
      <div className="grid grid-cols-2 gap-4 mb-6">
        <div className="bg-indigo-600 p-4 rounded-3xl text-white shadow-xl shadow-indigo-100">
          <p className="text-[10px] opacity-80 uppercase font-black tracking-widest mb-1">Ofertas no Ar</p>
          <p className="text-3xl font-black">{localPromos.length}</p>
        </div>
        <button 
          onClick={() => setShowModal(true)}
          className="bg-white p-4 rounded-3xl border-2 border-dashed border-indigo-200 flex flex-col items-center justify-center gap-1 group hover:bg-indigo-50 hover:border-indigo-400 transition-all"
        >
          <Plus className="text-indigo-600 group-hover:scale-110 transition-transform" size={24} />
          <span className="text-[10px] font-black text-indigo-600 uppercase">Nova Oferta</span>
        </button>
      </div>

      {/* Lista de Ofertas Ativas */}
      <div className="mb-4">
        <h3 className="text-sm font-black text-gray-900 uppercase tracking-widest px-1 mb-4">Minhas Ofertas Ativas</h3>
        <div className="space-y-3">
          {localPromos.map((promo) => (
            <div key={promo.id} className="bg-white p-3 rounded-2xl border border-gray-100 shadow-sm flex items-center gap-4 group">
              <div className="w-16 h-16 rounded-xl overflow-hidden bg-gray-100 relative shrink-0">
                {promo.videoUrl ? (
                  <div className="w-full h-full flex items-center justify-center">
                    <Film className="text-indigo-400" size={20} />
                    <video src={promo.videoUrl} className="absolute inset-0 w-full h-full object-cover opacity-50" />
                  </div>
                ) : (
                  <img src={promo.imageUrl} className="w-full h-full object-cover" />
                )}
              </div>
              <div className="flex-1 min-w-0">
                <div className="flex items-center gap-2">
                  <span className="text-[10px] font-black text-indigo-600 bg-indigo-50 px-2 py-0.5 rounded-full uppercase tracking-tighter">
                    {promo.discount}
                  </span>
                  <span className="text-[9px] font-bold text-gray-400 uppercase">Validade: {promo.expiresAt}</span>
                </div>
                <p className="text-xs text-gray-600 font-medium mt-1 truncate">{promo.description}</p>
              </div>
              <div className="flex items-center gap-2 px-2">
                <div className="text-center">
                   <p className="text-[10px] font-black text-gray-900 leading-none">{promo.likes}</p>
                   <p className="text-[8px] font-bold text-gray-400 uppercase">Likes</p>
                </div>
              </div>
            </div>
          ))}

          {localPromos.length === 0 && (
            <div className="py-12 text-center bg-white rounded-[32px] border-2 border-dashed border-gray-100">
              <Zap size={32} className="text-gray-200 mx-auto mb-3" />
              <p className="text-xs text-gray-400 font-bold uppercase tracking-widest">Nenhuma oferta publicada</p>
            </div>
          )}
        </div>
      </div>

      {/* Modal Profile */}
      {showProfileModal && (
        <div className="fixed inset-0 z-[110] bg-black/80 flex items-center justify-center p-4 backdrop-blur-md">
          <div className="bg-white w-full max-w-sm rounded-3xl p-6 relative shadow-2xl">
            <button onClick={() => setShowProfileModal(false)} className="absolute top-4 right-4 text-gray-400 p-2"><X size={24} /></button>
            <h3 className="text-xl font-black mb-6 italic tracking-tighter">PERFIL DA LOJA</h3>
            <div className="space-y-6 mb-8 text-center">
              <div className="flex flex-col items-center">
                <div className="relative group">
                  <img src={profileData.logo} className="w-24 h-24 rounded-[32px] object-cover border-4 border-indigo-50 shadow-xl" />
                  <label className="absolute inset-0 flex items-center justify-center bg-black/40 rounded-[32px] cursor-pointer opacity-0 group-hover:opacity-100 transition-opacity">
                    <Camera size={24} className="text-white" />
                    <input type="file" accept="image/*" className="hidden" onChange={handleLogoUpload} />
                  </label>
                </div>
                <span className="text-[10px] font-black text-indigo-600 uppercase mt-3 tracking-widest">Trocar Logo</span>
              </div>
              <div className="text-left">
                <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1 block ml-1">Nome Fantasia</label>
                <input value={profileData.name} onChange={(e) => setProfileData({...profileData, name: e.target.value})} type="text" className="w-full bg-gray-50 border border-gray-100 rounded-2xl p-4 text-sm focus:ring-2 focus:ring-indigo-500 outline-none font-bold" />
              </div>
            </div>
            <button onClick={handleUpdateProfile} className="w-full py-4 bg-indigo-600 rounded-2xl font-black text-white shadow-xl shadow-indigo-100 transition-all active:scale-95">SALVAR ALTERAÇÕES</button>
          </div>
        </div>
      )}

      {/* Modal New Promo - FORMULÁRIO COMPLETO */}
      {showModal && (
        <div className="fixed inset-0 z-[100] bg-black/80 flex items-center justify-center p-4 backdrop-blur-md">
          <div className="bg-white w-full max-w-sm rounded-[40px] p-7 relative shadow-2xl overflow-y-auto max-h-[90vh] no-scrollbar">
            <button onClick={() => setShowModal(false)} className="absolute top-5 right-5 text-gray-400 p-2 hover:bg-gray-50 rounded-full"><X size={24} /></button>
            <h3 className="text-2xl font-black mb-6 italic tracking-tighter">NOVA OFERTA</h3>

            <div className="space-y-5 mb-8">
              {/* Media Picker */}
              <div>
                <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest block mb-2 ml-1">Mídia (Imagem ou Vídeo)</label>
                <div className={`border-2 border-dashed rounded-[32px] p-8 flex flex-col items-center justify-center gap-3 cursor-pointer transition-all relative min-h-[180px] overflow-hidden ${mediaPreview ? 'border-indigo-400 bg-indigo-50' : 'border-gray-200 hover:bg-gray-50'}`}>
                  <input 
                    type="file" 
                    accept="image/*,video/*" 
                    onChange={handleMediaChange} 
                    className="absolute inset-0 opacity-0 cursor-pointer z-20" 
                  />

                  {mediaPreview ? (
                    <div className="absolute inset-0 w-full h-full flex items-center justify-center z-10 bg-white">
                      {mediaType === 'VIDEO' ? (
                        <video src={mediaPreview} className="w-full h-full object-cover" muted />
                      ) : (
                        <img src={mediaPreview} className="w-full h-full object-cover" />
                      )}
                      <div className="absolute bottom-3 right-3 bg-black/50 text-white p-2 rounded-full backdrop-blur-md">
                        {mediaType === 'VIDEO' ? <Film size={16} /> : <ImageIcon size={16} />}
                      </div>
                    </div>
                  ) : (
                    <>
                      <div className="w-14 h-14 bg-indigo-50 rounded-2xl flex items-center justify-center text-indigo-500 mb-1">
                        <Plus size={32} />
                      </div>
                      <span className="text-[10px] font-black text-gray-400 uppercase tracking-[0.2em] text-center">Selecionar do Dispositivo</span>
                    </>
                  )}
                </div>
              </div>

              {/* Descrição */}
              <div>
                <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest block mb-1 ml-1">Descrição da Promoção</label>
                <textarea 
                  value={formData.description} 
                  onChange={(e) => setFormData({...formData, description: e.target.value})} 
                  className="w-full bg-gray-50 border border-gray-100 rounded-2xl p-4 text-sm min-h-[100px] focus:ring-2 focus:ring-indigo-500 outline-none font-medium" 
                  placeholder="Ex: Combo Família - Pizza GG + Refri 2L + Borda Recheada..." 
                />
              </div>

              <div className="grid grid-cols-2 gap-4">
                {/* Desconto */}
                <div>
                  <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest block mb-1 ml-1">Desconto (%)</label>
                  <div className="relative">
                    <Percent className="absolute left-4 top-1/2 -translate-y-1/2 text-indigo-400" size={16} />
                    <input 
                      type="number"
                      value={formData.discount} 
                      onChange={(e) => setFormData({...formData, discount: e.target.value})} 
                      className="w-full bg-gray-50 border border-gray-100 rounded-2xl py-4 pl-10 pr-4 text-sm focus:ring-2 focus:ring-indigo-500 outline-none font-black" 
                      placeholder="Ex: 30"
                    />
                  </div>
                </div>

                {/* Validade */}
                <div>
                  <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest block mb-1 ml-1">Válido Até</label>
                  <div className="relative">
                    <Calendar className="absolute left-4 top-1/2 -translate-y-1/2 text-indigo-400" size={16} />
                    <input 
                      type="date"
                      value={formData.expiresAt} 
                      onChange={(e) => setFormData({...formData, expiresAt: e.target.value})} 
                      className="w-full bg-gray-50 border border-gray-100 rounded-2xl py-4 pl-10 pr-4 text-xs focus:ring-2 focus:ring-indigo-500 outline-none font-bold" 
                    />
                  </div>
                </div>
              </div>
            </div>

            <button 
              onClick={handleCreatePromo} 
              disabled={loading} 
              className="w-full py-5 bg-indigo-600 rounded-[24px] font-black text-white shadow-xl shadow-indigo-100 flex items-center justify-center gap-3 transition-all active:scale-95 disabled:opacity-50"
            >
              {loading ? <Loader2 className="animate-spin" size={24} /> : <Zap size={20} />}
              {loading ? 'PUBLICANDO OFERTA...' : 'PUBLICAR AGORA'}
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

export default MerchantDashboard;

import React, { useState, useEffect, useMemo } from 'react';
import { Plus, CheckCircle, Loader2, X, Trash2, ShieldCheck, Zap, Camera, Edit3, LogOut, Film, Image as ImageIcon, Calendar, Percent, Trash, Eye, Heart, Bookmark, TrendingUp, BarChart3 } from 'lucide-react';
import { saveLocalPromotion, clearLocalPromotions, getLocalPromotions, getMerchantProfile, saveMerchantProfile, MerchantProfile, setAuthUser } from '../constants';
import { Promotion } from '../types';

const MerchantDashboard: React.FC = () => {
  const [showModal, setShowModal] = useState(false);
  const [showProfileModal, setShowProfileModal] = useState(false);
  const [loading, setLoading] = useState(false);
  const [localPromos, setLocalPromos] = useState<Promotion[]>(getLocalPromotions());
  const [merchant, setMerchant] = useState<MerchantProfile>(getMerchantProfile());

  const [formData, setFormData] = useState({
    description: '',
    discount: '',
    expiresAt: ''
  });

  const [mediaFile, setMediaFile] = useState<File | null>(null);
  const [mediaPreview, setMediaPreview] = useState<string | null>(null);
  const [mediaType, setMediaType] = useState<'IMAGE' | 'VIDEO' | null>(null);
  const [profileData, setProfileData] = useState<MerchantProfile>(merchant);

  useEffect(() => {
    const handleUpdate = () => {
      setLocalPromos(getLocalPromotions());
      setMerchant(getMerchantProfile());
    };
    window.addEventListener('storage_update', handleUpdate);
    window.addEventListener('merchant_update', handleUpdate);
    return () => {
      window.removeEventListener('storage_update', handleUpdate);
      window.removeEventListener('merchant_update', handleUpdate);
    };
  }, []);

  // Cálculo de estatísticas agregadas (Simulando visualizações e salvamentos baseados nos likes)
  const stats = useMemo(() => {
    const totalLikes = localPromos.reduce((acc, curr) => acc + curr.likes, 0);
    const totalViews = localPromos.length * 142 + totalLikes * 3; // Simulação
    const totalSaves = Math.floor(totalLikes * 0.4); // Simulação

    return {
      views: totalViews,
      likes: totalLikes,
      saves: totalSaves,
      engagement: totalViews > 0 ? ((totalLikes + totalSaves) / totalViews * 100).toFixed(1) : '0'
    };
  }, [localPromos]);

  // Dados para o Gráfico (Simulados para os últimos 7 dias)
  const chartData = [32, 45, 28, 65, 48, 72, 58];
  const maxVal = Math.max(...chartData);

  const handleMediaChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setMediaFile(file);
      const isVideo = file.type.startsWith('video/');
      setMediaType(isVideo ? 'VIDEO' : 'IMAGE');

      const reader = new FileReader();
      reader.onloadend = () => {
        setMediaPreview(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleCreatePromo = async () => {
    if (!formData.description || !mediaPreview || !formData.discount || !formData.expiresAt) {
      alert("⚠️ Por favor, preencha todos os campos e adicione uma imagem ou vídeo.");
      return;
    }

    setLoading(true);
    const [year, month, day] = formData.expiresAt.split('-');
    const formattedDate = `${day}/${month}/${year}`;

    const newPromo: Promotion = {
      id: `local_${Date.now()}`,
      storeId: 'lojista_local',
      storeName: merchant.name,
      storeLogo: merchant.logo,
      imageUrl: mediaType === 'IMAGE' ? mediaPreview : '',
      videoUrl: mediaType === 'VIDEO' ? mediaPreview : undefined,
      description: formData.description,
      discount: formData.discount.includes('%') ? formData.discount : `${formData.discount}% OFF`,
      expiresAt: formattedDate,
      likes: 0,
      saved: false
    };

    saveLocalPromotion(newPromo);
    setLoading(false);
    setShowModal(false);
    setFormData({ description: '', discount: '', expiresAt: '' });
    setMediaFile(null);
    setMediaPreview(null);
    setMediaType(null);
  };

  const handleUpdateProfile = () => {
    if (!profileData.name) {
      alert("O nome da empresa é obrigatório.");
      return;
    }
    saveMerchantProfile(profileData);
    setShowProfileModal(false);
  };

  const handleLogoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const logoFile = e.target.files?.[0];
    if (logoFile) {
      const reader = new FileReader();
      reader.onloadend = () => setProfileData({ ...profileData, logo: reader.result as string });
      reader.readAsDataURL(logoFile);
    }
  };

  const handleClear = () => {
    if (confirm("Deseja apagar todas as suas promoções? Isso removerá as ofertas do feed público.")) {
      clearLocalPromotions();
    }
  };

  const handleLogout = () => {
    if (confirm("Deseja realmente sair da sua conta de lojista?")) {
      setAuthUser(null);
    }
  };

  return (
    <div className="p-4 h-full bg-gray-50 overflow-y-auto pb-24 text-left">
      {/* Header */}
      <div className="flex items-center justify-between mb-8">
        <div>
          <h1 className="text-2xl font-black text-gray-900 tracking-tighter italic">DASHBOARD</h1>
          <div className="flex items-center gap-1.5 mt-1">
             <span className="flex items-center gap-1 text-[10px] font-bold text-indigo-600 bg-indigo-50 px-2 py-0.5 rounded-full border border-indigo-100 uppercase tracking-widest">
                <ShieldCheck size={10} /> Conta Verificada
              </span>
          </div>
        </div>
        <div className="flex items-center gap-2">
          <button 
            onClick={handleClear}
            className="bg-white p-3 rounded-2xl border border-gray-200 shadow-sm text-gray-400 hover:text-red-600 transition-colors"
            title="Limpar Ofertas"
          >
            <Trash size={20} />
          </button>
          <button 
            onClick={handleLogout}
            className="bg-rose-600 p-3 rounded-2xl shadow-lg shadow-rose-100 text-white hover:bg-rose-700 transition-all active:scale-90"
            title="Sair"
          >
            <LogOut size={20} />
          </button>
        </div>
      </div>

      {/* Perfil Card */}
      <div className="bg-white p-5 rounded-[32px] border border-gray-100 shadow-sm mb-6 flex items-center gap-4 relative overflow-hidden">
        <div className="absolute top-0 right-0 w-24 h-24 bg-indigo-50 rounded-full -mr-12 -mt-12 opacity-50" />
        <button 
          onClick={() => { setProfileData(merchant); setShowProfileModal(true); }}
          className="absolute top-4 right-4 p-2 text-indigo-600 hover:bg-indigo-50 rounded-full transition-colors z-10"
        >
          <Edit3 size={18} />
        </button>
        <img src={merchant.logo} className="w-16 h-16 rounded-2xl object-cover border-2 border-indigo-100 shadow-sm z-10" />
        <div className="z-10">
          <h2 className="font-black text-gray-900 text-lg leading-tight">{merchant.name}</h2>
          <p className="text-[10px] text-gray-400 font-bold uppercase tracking-[0.2em] mt-1">Lojista Parceiro</p>
        </div>
      </div>

      {/* Grid de Indicadores de Interação */}
      <div className="grid grid-cols-2 gap-3 mb-6">
        <div className="bg-white p-4 rounded-3xl border border-gray-100 shadow-sm">
          <div className="flex items-center justify-between mb-2">
            <div className="p-1.5 bg-blue-50 text-blue-600 rounded-lg"><Eye size={16} /></div>
            <span className="text-[10px] text-green-500 font-bold">+12%</span>
          </div>
          <p className="text-xl font-black text-gray-900">{stats.views}</p>
          <p className="text-[9px] text-gray-400 font-bold uppercase tracking-widest">Visualizações</p>
        </div>

        <div className="bg-white p-4 rounded-3xl border border-gray-100 shadow-sm">
          <div className="flex items-center justify-between mb-2">
            <div className="p-1.5 bg-rose-50 text-rose-600 rounded-lg"><Heart size={16} /></div>
            <span className="text-[10px] text-green-500 font-bold">+5%</span>
          </div>
          <p className="text-xl font-black text-gray-900">{stats.likes}</p>
          <p className="text-[9px] text-gray-400 font-bold uppercase tracking-widest">Curtidas</p>
        </div>

        <div className="bg-white p-4 rounded-3xl border border-gray-100 shadow-sm">
          <div className="flex items-center justify-between mb-2">
            <div className="p-1.5 bg-amber-50 text-amber-600 rounded-lg"><Bookmark size={16} /></div>
            <span className="text-[10px] text-green-500 font-bold">+8%</span>
          </div>
          <p className="text-xl font-black text-gray-900">{stats.saves}</p>
          <p className="text-[9px] text-gray-400 font-bold uppercase tracking-widest">Salvos</p>
        </div>

        <div className="bg-white p-4 rounded-3xl border border-gray-100 shadow-sm">
          <div className="flex items-center justify-between mb-2">
            <div className="p-1.5 bg-indigo-50 text-indigo-600 rounded-lg"><TrendingUp size={16} /></div>
            <span className="text-[10px] text-indigo-400 font-bold">Ótimo</span>
          </div>
          <p className="text-xl font-black text-gray-900">{stats.engagement}%</p>
          <p className="text-[9px] text-gray-400 font-bold uppercase tracking-widest">Engajamento</p>
        </div>
      </div>

      {/* Gráfico de Desempenho */}
      <div className="bg-white p-6 rounded-[32px] border border-gray-100 shadow-sm mb-6">
        <div className="flex items-center justify-between mb-6">
          <div className="flex items-center gap-2">
            <BarChart3 size={18} className="text-indigo-600" />
            <h3 className="text-xs font-black text-gray-900 uppercase tracking-widest">Desempenho Semanal</h3>
          </div>
          <select className="bg-transparent text-[10px] font-bold text-gray-400 uppercase outline-none">
            <option>Últimos 7 dias</option>
            <option>Últimos 30 dias</option>
          </select>
        </div>

        <div className="flex items-end justify-between h-32 gap-2 px-2">
          {chartData.map((val, i) => (
            <div key={i} className="flex-1 flex flex-col items-center gap-2 group">
              <div 
                style={{ height: `${(val / maxVal) * 100}%` }}
                className="w-full bg-indigo-100 rounded-t-lg group-hover:bg-indigo-600 transition-all duration-300 relative"
              >
                <div className="absolute -top-6 left-1/2 -translate-x-1/2 bg-gray-900 text-white text-[8px] font-bold py-1 px-2 rounded opacity-0 group-hover:opacity-100 transition-opacity">
                  {val}
                </div>
              </div>
              <span className="text-[8px] font-bold text-gray-300 uppercase">
                {['S', 'T', 'Q', 'Q', 'S', 'S', 'D'][i]}
              </span>
            </div>
          ))}
        </div>
      </div>

      {/* Botão de Ação Flutuante Simulado no fluxo */}
      <button 
        onClick={() => setShowModal(true)}
        className="w-full bg-indigo-600 hover:bg-indigo-700 text-white font-black py-5 rounded-[24px] flex items-center justify-center gap-3 shadow-xl shadow-indigo-100 transition-all active:scale-95 mb-10"
      >
        <Plus size={24} />
        CRIAR NOVA OFERTA
      </button>

      {/* Lista de Ofertas Ativas */}
      <div className="mb-4">
        <div className="flex items-center justify-between mb-4 px-1">
          <h3 className="text-sm font-black text-gray-900 uppercase tracking-widest">Minhas Ofertas</h3>
          <span className="text-[10px] font-bold text-gray-400 uppercase">{localPromos.length} ATIVAS</span>
        </div>
        <div className="space-y-3">
          {localPromos.map((promo) => (
            <div key={promo.id} className="bg-white p-3 rounded-2xl border border-gray-100 shadow-sm flex items-center gap-4 group">
              <div className="w-16 h-16 rounded-xl overflow-hidden bg-gray-100 relative shrink-0">
                {promo.videoUrl ? (
                  <div className="w-full h-full flex items-center justify-center">
                    <Film className="text-indigo-400" size={20} />
                    <video src={promo.videoUrl} className="absolute inset-0 w-full h-full object-cover opacity-50" />
                  </div>
                ) : (
                  <img src={promo.imageUrl} className="w-full h-full object-cover" />
                )}
              </div>
              <div className="flex-1 min-w-0">
                <div className="flex items-center gap-2">
                  <span className="text-[10px] font-black text-indigo-600 bg-indigo-50 px-2 py-0.5 rounded-full uppercase tracking-tighter">
                    {promo.discount}
                  </span>
                  <span className="text-[9px] font-bold text-gray-400 uppercase">{promo.expiresAt}</span>
                </div>
                <p className="text-xs text-gray-600 font-medium mt-1 truncate">{promo.description}</p>
              </div>
              <div className="flex items-center gap-3 px-2 border-l border-gray-50">
                <div className="text-center">
                   <p className="text-[10px] font-black text-rose-500 leading-none">{promo.likes}</p>
                   <Heart size={10} className="text-rose-500 mx-auto mt-1" fill="currentColor" />
                </div>
              </div>
            </div>
          ))}

          {localPromos.length === 0 && (
            <div className="py-12 text-center bg-white rounded-[32px] border-2 border-dashed border-gray-100">
              <Zap size={32} className="text-gray-200 mx-auto mb-3" />
              <p className="text-xs text-gray-400 font-bold uppercase tracking-widest">Nenhuma oferta publicada</p>
            </div>
          )}
        </div>
      </div>

      {/* Modal Profile */}
