export const getStores = (): Store[] => {
  const stored = localStorage.getItem(STORES_KEY);
  return stored ? JSON.parse(stored) : INITIAL_STORES;
};

export const saveStore = (store: Store) => {
  const stores = getStores();
  localStorage.setItem(STORES_KEY, JSON.stringify([...stores, store]));
  window.dispatchEvent(new Event('stores_update'));
};

export const getAuthUser = (): AuthUser | null => {
  const stored = localStorage.getItem(AUTH_KEY);
  return stored ? JSON.parse(stored) : null;
};

export const setAuthUser = (user: AuthUser | null) => {
  if (user) localStorage.setItem(AUTH_KEY, JSON.stringify(user));
  else localStorage.removeItem(AUTH_KEY);
  window.dispatchEvent(new Event('auth_change'));
};

export const registerConsumer = (name: string, email: string) => {
  const consumers = JSON.parse(localStorage.getItem(CONSUMERS_KEY) || '[]');
  const newUser = { id: Date.now().toString(), name, email, role: 'CONSUMER' as UserRole };
  localStorage.setItem(CONSUMERS_KEY, JSON.stringify([...consumers, newUser]));
  return newUser;
};

export const getLocalPromotions = (): Promotion[] => {
  const stored = localStorage.getItem(PROMOS_KEY);
  return stored ? JSON.parse(stored) : [];
};

export const saveLocalPromotion = (promo: Promotion) => {
  const current = getLocalPromotions();
  localStorage.setItem(PROMOS_KEY, JSON.stringify([promo, ...current]));
  window.dispatchEvent(new Event('storage_update'));
};

export const clearLocalPromotions = () => {
  localStorage.removeItem(PROMOS_KEY);
  window.dispatchEvent(new Event('storage_update'));
};

