  const stored = localStorage.getItem(MERCHANT_KEY);
  return stored ? JSON.parse(stored) : INITIAL_MERCHANT;
};

export const saveMerchantProfile = (profile: MerchantProfile) => {
  localStorage.setItem(MERCHANT_KEY, JSON.stringify(profile));
  window.dispatchEvent(new Event('merchant_update'));
};

