import React, { useState, useEffect, useMemo } from 'react';
import { Plus, CheckCircle, Loader2, X, Trash2, ShieldCheck, Zap, Camera, Edit3, LogOut, Film, Image as ImageIcon, Calendar, Percent, Trash, Eye, Heart, Bookmark, TrendingUp, BarChart3, Wand2 } from 'lucide-react';
import { saveLocalPromotion, clearLocalPromotions, getLocalPromotions, getMerchantProfile, saveMerchantProfile, MerchantProfile, setAuthUser } from '../constants';
import { Promotion } from '../types';

const MerchantDashboard: React.FC = () => {
  const [showModal, setShowModal] = useState(false);
  const [showProfileModal, setShowProfileModal] = useState(false);
  const [loading, setLoading] = useState(false);
  const [localPromos, setLocalPromos] = useState<Promotion[]>(getLocalPromotions());
  const [merchant, setMerchant] = useState<MerchantProfile>(getMerchantProfile());

  const [formData, setFormData] = useState({
    description: '',
    discount: '',
    expiresAt: ''
  });

  const [mediaFile, setMediaFile] = useState<File | null>(null);
  const [mediaPreview, setMediaPreview] = useState<string | null>(null);
  const [mediaType, setMediaType] = useState<'IMAGE' | 'VIDEO' | null>(null);
  const [profileData, setProfileData] = useState<MerchantProfile>(merchant);

  useEffect(() => {
    const handleUpdate = () => {
      setLocalPromos(getLocalPromotions());
      setMerchant(getMerchantProfile());
    };
    window.addEventListener('storage_update', handleUpdate);
    window.addEventListener('merchant_update', handleUpdate);
    return () => {
      window.removeEventListener('storage_update', handleUpdate);
      window.removeEventListener('merchant_update', handleUpdate);
    };
  }, []);

  const stats = useMemo(() => {
    const totalLikes = localPromos.reduce((acc, curr) => acc + curr.likes, 0);
    const totalViews = localPromos.length * 142 + totalLikes * 3;
    const totalSaves = Math.floor(totalLikes * 0.4);

    return {
      views: totalViews,
      likes: totalLikes,
      saves: totalSaves,
      engagement: totalViews > 0 ? ((totalLikes + totalSaves) / totalViews * 100).toFixed(1) : '0'
    };
  }, [localPromos]);

  const chartData = [32, 45, 28, 65, 48, 72, 58];
  const maxVal = Math.max(...chartData);

  const handleFillExample = () => {
    setFormData({
      description: 'Super Combo Smash Burger: 2 Burgers + Batata G + Bebida. Só hoje!',
      discount: '30',
      expiresAt: '2025-12-31'
    });
    setMediaPreview('https://images.unsplash.com/photo-1594212699903-ec8a3eca50f5?w=800&h=1200&fit=crop');
    setMediaType('IMAGE');
  };

  const handleMediaChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setMediaFile(file);
      const isVideo = file.type.startsWith('video/');
      setMediaType(isVideo ? 'VIDEO' : 'IMAGE');
      const reader = new FileReader();
      reader.onloadend = () => setMediaPreview(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  const handleCreatePromo = async () => {
    if (!formData.description || !mediaPreview || !formData.discount || !formData.expiresAt) {
      alert("⚠️ Preencha todos os campos.");
      return;
    }

    setLoading(true);
    await new Promise(r => setTimeout(r, 800)); // Pequeno delay visual
    const [year, month, day] = formData.expiresAt.split('-');
    const formattedDate = `${day}/${month}/${year}`;

    const newPromo: Promotion = {
      id: `local_${Date.now()}`,
      storeId: 'lojista_local',
      storeName: merchant.name,
      storeLogo: merchant.logo,
      imageUrl: mediaType === 'IMAGE' ? mediaPreview : 'https://images.unsplash.com/photo-1594212699903-ec8a3eca50f5?w=100&h=100&fit=crop',
      videoUrl: mediaType === 'VIDEO' ? mediaPreview : undefined,
      description: formData.description,
      discount: `${formData.discount}% OFF`,
      expiresAt: formattedDate,
      likes: 0,
      saved: false
    };

    saveLocalPromotion(newPromo);
    setLoading(false);
    setShowModal(false);
    setFormData({ description: '', discount: '', expiresAt: '' });
    setMediaPreview(null);
    setMediaType(null);
  };

  const handleLogout = () => {
    if (confirm("Sair do Dashboard?")) setAuthUser(null);
  };

  return (
    <div className="p-4 h-full bg-gray-50 overflow-y-auto pb-24 text-left no-scrollbar">
      {/* Header */}
      <div className="flex items-center justify-between mb-8">
        <div>
          <h1 className="text-2xl font-black text-gray-900 tracking-tighter italic">MEU NEGÓCIO</h1>
          <div className="flex items-center gap-1.5 mt-1">
             <span className="flex items-center gap-1 text-[10px] font-black text-emerald-600 bg-emerald-50 px-2 py-0.5 rounded-full border border-emerald-100 uppercase tracking-widest">
                <ShieldCheck size={10} /> Canal Oficial
              </span>
          </div>
        </div>
        <div className="flex items-center gap-2">
          <button onClick={handleLogout} className="bg-rose-600 p-3 rounded-2xl shadow-lg shadow-rose-100 text-white hover:bg-rose-700 transition-all active:scale-90">
            <LogOut size={20} />
          </button>
        </div>
      </div>

      {/* Stats Quick View */}
      <div className="grid grid-cols-2 gap-3 mb-6">
        <div className="bg-white p-4 rounded-3xl border border-gray-100 shadow-sm">
          <p className="text-[9px] text-gray-400 font-black uppercase tracking-widest mb-1">Visualizações</p>
          <div className="flex items-center gap-2">
            <span className="text-xl font-black">{stats.views}</span>
            <span className="text-[9px] text-emerald-500 font-bold">+5%</span>
          </div>
