    const totalLikes = localPromos.reduce((acc, curr) => acc + curr.likes, 0);
    const totalViews = localPromos.length * 142 + totalLikes * 3;
    const totalSaves = Math.floor(totalLikes * 0.4);

    return {
      views: totalViews,
      likes: totalLikes,
      saves: totalSaves,
      engagement: totalViews > 0 ? ((totalLikes + totalSaves) / totalViews * 100).toFixed(1) : '0'
    };
