                <textarea value={formData.description} onChange={(e) => setFormData({...formData, description: e.target.value})} className="w-full bg-gray-50 border border-gray-100 rounded-2xl p-4 text-sm min-h-[80px] outline-none font-medium" placeholder="Ex: Toda a loja com..." />
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest block mb-1">Desconto (%)</label>
                  <input type="number" value={formData.discount} onChange={(e) => setFormData({...formData, discount: e.target.value})} className="w-full bg-gray-50 border border-gray-100 rounded-xl p-4 text-sm font-black outline-none" placeholder="30" />
                </div>
                <div>
                  <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest block mb-1">Válido Até</label>
                  <input type="date" value={formData.expiresAt} onChange={(e) => setFormData({...formData, expiresAt: e.target.value})} className="w-full bg-gray-50 border border-gray-100 rounded-xl p-4 text-xs font-bold outline-none" />
                </div>
              </div>
            </div>

            <button onClick={handleCreatePromo} disabled={loading} className="w-full py-5 bg-indigo-600 rounded-[24px] font-black text-white shadow-xl flex items-center justify-center gap-3 transition-all active:scale-95 disabled:opacity-50">
              {loading ? <Loader2 className="animate-spin" size={24} /> : <Zap size={20} />}
              {loading ? 'ENVIANDO...' : 'PUBLICAR NO FEED'}
            </button>
          </div>
        </div>
      )}

      {showProfileModal && (
        <div className="fixed inset-0 z-[110] bg-black/80 flex items-center justify-center p-4 backdrop-blur-md">
          <div className="bg-white w-full max-w-sm rounded-[40px] p-7 relative shadow-2xl">
            <button onClick={() => setShowProfileModal(false)} className="absolute top-6 right-6 text-gray-400 p-2"><X size={24} /></button>
            <h3 className="text-xl font-black mb-6 italic tracking-tighter uppercase">PERFIL DA EMPRESA</h3>
            <div className="space-y-6 mb-8 text-center">
              <div className="flex flex-col items-center">
                <div className="relative group">
                  <img src={profileData.logo} className="w-24 h-24 rounded-[32px] object-cover border-4 border-indigo-50 shadow-xl" />
                  <label className="absolute inset-0 flex items-center justify-center bg-black/40 rounded-[32px] cursor-pointer opacity-0 group-hover:opacity-100 transition-opacity">
                    <Camera size={24} className="text-white" />
                    <input type="file" accept="image/*" className="hidden" onChange={(e) => {
                      const logoFile = e.target.files?.[0];
                      if (logoFile) {
                        const reader = new FileReader();
                        reader.onloadend = () => setProfileData({ ...profileData, logo: reader.result as string });
                        reader.readAsDataURL(logoFile);
                      }
                    }} />
                  </label>
                </div>
                <span className="text-[10px] font-black text-indigo-600 uppercase mt-3 tracking-widest">Alterar Identidade</span>
              </div>
              <div className="text-left">
                <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1 block ml-1">Nome Fantasia</label>
                <input value={profileData.name} onChange={(e) => setProfileData({...profileData, name: e.target.value})} type="text" className="w-full bg-gray-50 border border-gray-100 rounded-2xl p-4 text-sm focus:ring-2 focus:ring-indigo-500 outline-none font-bold" />
              </div>
            </div>
            <button onClick={() => {
              saveMerchantProfile(profileData);
              setShowProfileModal(false);
            }} className="w-full py-5 bg-indigo-600 rounded-[24px] font-black text-white shadow-xl shadow-indigo-100 transition-all active:scale-95">SALVAR PERFIL</button>
          </div>
        </div>
      )}
    </div>
  );
};

