          setAuthUser({
            id: userCred.user.uid,
            email: formData.email,
            name: 'Usuário',
            role: 'CONSUMER'
          });
        }
      }
    } catch (error: any) {
      alert("Erro na autenticação: " + error.message);
    } finally {
      setLoading(false);
    }
  };

  const switchRole = (newRole: UserRole) => {
    setRole(newRole);
    setMode('LOGIN');
