import React, { useState, useEffect, useMemo } from 'react';
import { Plus, CheckCircle, Loader2, X, Trash2, ShieldCheck, Zap, Camera, Edit3, LogOut, Film, Image as ImageIcon, Calendar, Percent, Trash, Eye, Heart, Bookmark, TrendingUp, BarChart3, Wand2, LayoutGrid } from 'lucide-react';
import { saveLocalPromotion, getAuthUser, setAuthUser } from '../constants';
import { storage } from '../firebase';
import { ref, uploadBytes, getDownloadURL } from 'https://www.gstatic.com/firebasejs/10.7.1/firebase-storage.js';
import { Promotion, ViewType } from '../types';

interface MerchantDashboardProps {
  onViewChange?: (view: ViewType) => void;
}

const MerchantDashboard: React.FC<MerchantDashboardProps> = ({ onViewChange }) => {
  const user = getAuthUser();
  const [showModal, setShowModal] = useState(false);
  const [loading, setLoading] = useState(false);

  const [formData, setFormData] = useState({
    description: '',
    discount: '',
    expiresAt: ''
  });

  const [mediaFile, setMediaFile] = useState<File | null>(null);
  const [mediaPreview, setMediaPreview] = useState<string | null>(null);

  const handleMediaChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      setMediaFile(file);
      const reader = new FileReader();
      reader.onloadend = () => setMediaPreview(reader.result as string);
      reader.readAsDataURL(file);
    }
  };

  const handleCreatePromo = async () => {
    if (!formData.description || !mediaFile || !formData.discount || !formData.expiresAt) {
      alert("⚠️ Preencha todos os campos e selecione uma imagem.");
      return;
    }

    setLoading(true);
    try {
      // 1. Upload para o Firebase Storage
      const storageRef = ref(storage, `promotions/${Date.now()}_${mediaFile.name}`);
      const uploadSnap = await uploadBytes(storageRef, mediaFile);
      const downloadUrl = await getDownloadURL(uploadSnap.ref);

      // 2. Salvar metadados no Firestore
      const [year, month, day] = formData.expiresAt.split('-');

      await saveLocalPromotion({
        storeId: user?.merchantId || 'unknown',
        storeName: user?.name || 'Minha Loja',
        storeLogo: 'https://images.unsplash.com/photo-1552566626-52f8b828add9?w=100&h=100&fit=crop', // Fallback
        imageUrl: downloadUrl,
        description: formData.description,
        discount: `${formData.discount}% OFF`,
        expiresAt: `${day}/${month}/${year}`,
        likes: 0,
        saved: false
      });

      setShowModal(false);
      setFormData({ description: '', discount: '', expiresAt: '' });
      setMediaPreview(null);
      setMediaFile(null);
      alert("🎉 Oferta publicada com sucesso!");
    } catch (err: any) {
      alert("Erro ao publicar: " + err.message);
    } finally {
      setLoading(false);
    }
  };

  const handleLogout = () => {
    if (confirm("Sair do Dashboard?")) setAuthUser(null);
  };

  return (
    <div className="p-4 h-full bg-gray-50 overflow-y-auto pb-24 text-left no-scrollbar">
      <div className="flex items-center justify-between mb-8">
        <div>
          <h1 className="text-2xl font-black text-gray-900 tracking-tighter italic uppercase">Dashboard Cloud</h1>
          <p className="text-[10px] text-indigo-600 font-bold tracking-widest uppercase">Sincronizado em tempo real</p>
        </div>
        <div className="flex items-center gap-2">
          <button onClick={() => onViewChange?.('FEED')} className="bg-white p-3 rounded-2xl border border-gray-200 shadow-sm text-indigo-600"><LayoutGrid size={20} /></button>
          <button onClick={handleLogout} className="bg-rose-600 p-3 rounded-2xl text-white"><LogOut size={20} /></button>
        </div>
      </div>

      <button onClick={() => setShowModal(true)} className="w-full bg-indigo-600 hover:bg-indigo-700 text-white font-black py-5 rounded-[24px] flex items-center justify-center gap-3 shadow-xl transition-all active:scale-95 mb-6">
        <Plus size={24} /> NOVA OFERTA CLOUD
      </button>

      {/* Modal simplificado para brevidade */}
      {showModal && (
        <div className="fixed inset-0 z-[100] bg-black/80 flex items-center justify-center p-4 backdrop-blur-md">
          <div className="bg-white w-full max-w-sm rounded-[40px] p-7 relative">
            <button onClick={() => setShowModal(false)} className="absolute top-5 right-5 text-gray-400 p-2"><X size={24} /></button>
            <h3 className="text-xl font-black italic mb-6">NOVA OFERTA</h3>

            <div className="space-y-4 mb-6">
              <div className="border-2 border-dashed rounded-[32px] p-6 flex flex-col items-center justify-center gap-2 relative min-h-[160px] overflow-hidden">
                <input type="file" accept="image/*" onChange={handleMediaChange} className="absolute inset-0 opacity-0 cursor-pointer z-20" />
                {mediaPreview ? <img src={mediaPreview} className="w-full h-full object-cover absolute inset-0" /> : <span className="text-[10px] font-black text-gray-400 uppercase">Selecione uma imagem</span>}
              </div>
              <textarea placeholder="Descrição..." value={formData.description} onChange={e => setFormData({...formData, description: e.target.value})} className="w-full bg-gray-50 border p-4 rounded-2xl text-sm outline-none" />
              <div className="grid grid-cols-2 gap-4">
                <input type="number" placeholder="Desconto %" value={formData.discount} onChange={e => setFormData({...formData, discount: e.target.value})} className="bg-gray-50 border p-4 rounded-xl text-sm" />
                <input type="date" value={formData.expiresAt} onChange={e => setFormData({...formData, expiresAt: e.target.value})} className="bg-gray-50 border p-4 rounded-xl text-xs" />
              </div>
            </div>

            <button onClick={handleCreatePromo} disabled={loading} className="w-full py-5 bg-indigo-600 rounded-[24px] font-black text-white flex items-center justify-center gap-3 disabled:opacity-50">
              {loading ? <Loader2 className="animate-spin" size={24} /> : <Zap size={20} />}
              {loading ? 'PUBLICANDO...' : 'PUBLICAR NO FIREBASE'}
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

export default MerchantDashboard;

import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import FeedScreen from './components/FeedScreen';
import ExploreScreen from './components/ExploreScreen';
import MerchantDashboard from './components/MerchantDashboard';
import ProfileScreen from './components/ProfileScreen';
import AuthScreen from './components/AuthScreen';
import AdminDashboard from './components/AdminDashboard';
import StoreProfileScreen from './components/StoreProfileScreen';
import { ViewType, AuthUser, Store } from './types';
import { getAuthUser, getStoreById } from './constants';
import { auth } from './firebase';
import { onAuthStateChanged } from 'https://www.gstatic.com/firebasejs/10.7.1/firebase-auth.js';

const App: React.FC = () => {
  const [user, setUser] = useState<AuthUser | null>(getAuthUser());
  const [currentView, setCurrentView] = useState<ViewType>('AUTH');
  const [selectedStore, setSelectedStore] = useState<Store | null>(null);

  useEffect(() => {
    // Sincroniza com o Firebase Auth
    const unsubscribe = onAuthStateChanged(auth, (firebaseUser) => {
      if (!firebaseUser) {
        setUser(null);
        setCurrentView('AUTH');
      }
    });

    const handleAuthChange = () => {
      const newUser = getAuthUser();
      setUser(newUser);

      if (newUser) {
        if (newUser.role === 'ADMIN') setCurrentView('ADMIN_STORES');
        else if (newUser.role === 'MERCHANT') setCurrentView('MERCHANT');
        else setCurrentView('FEED');
      } else {
        setCurrentView('AUTH');
      }
    };

    handleAuthChange();
    window.addEventListener('auth_change', handleAuthChange);
    return () => {
      window.removeEventListener('auth_change', handleAuthChange);
      unsubscribe();
    };
  }, []);

  const handleOpenStoreProfile = async (storeId: string) => {
    const store = await getStoreById(storeId);
    if (store) {
      setSelectedStore(store);
      setCurrentView('STORE_PROFILE');
    }
  };

  const renderContent = () => {
    if (!user) return <AuthScreen />;

    switch (currentView) {
      case 'FEED': 
        return <FeedScreen onStoreClick={handleOpenStoreProfile} />;
      case 'EXPLORE': 
        return <ExploreScreen />;
      case 'MERCHANT': 
        return <MerchantDashboard onViewChange={setCurrentView} />;
      case 'PROFILE': 
        return <ProfileScreen />;
      case 'ADMIN_STORES': 
        return <AdminDashboard />;
      case 'STORE_PROFILE': 
        return selectedStore ? (
          <StoreProfileScreen 
            store={selectedStore} 
            onBack={() => setCurrentView('FEED')} 
          />
        ) : <FeedScreen onStoreClick={handleOpenStoreProfile} />;
      default: 
        return <FeedScreen onStoreClick={handleOpenStoreProfile} />;
    }
  };

  return (
    <div className="min-h-screen bg-neutral-950 flex justify-center items-center overflow-hidden">
      <div className="fixed inset-0 pointer-events-none opacity-20 overflow-hidden hidden sm:block">
        <div className="absolute top-[-10%] left-[-10%] w-[40%] h-[40%] bg-indigo-600 blur-[120px] rounded-full" />
        <div className="absolute bottom-[-10%] right-[-10%] w-[40%] h-[40%] bg-rose-600 blur-[120px] rounded-full" />
      </div>

      <Layout activeView={currentView} onViewChange={setCurrentView} user={user}>
        <div className="h-full w-full animate-fade-in">
          {renderContent()}
        </div>
      </Layout>
    </div>
  );
};

export default App;

