import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import FeedScreen from './components/FeedScreen';
import ExploreScreen from './components/ExploreScreen';
import MerchantDashboard from './components/MerchantDashboard';
import ProfileScreen from './components/ProfileScreen';
import AuthScreen from './components/AuthScreen';
import AdminDashboard from './components/AdminDashboard';
import StoreProfileScreen from './components/StoreProfileScreen';
import { ViewType, AuthUser, Store } from './types';
import { getAuthUser, getStoreById } from './constants';
import { auth } from './firebase';
import { onAuthStateChanged } from 'https://www.gstatic.com/firebasejs/10.7.1/firebase-auth.js';

const App: React.FC = () => {
  const [user, setUser] = useState<AuthUser | null>(getAuthUser());
  const [currentView, setCurrentView] = useState<ViewType>('AUTH');
  const [selectedStore, setSelectedStore] = useState<Store | null>(null);

  useEffect(() => {
    // Sincroniza com o Firebase Auth
    const unsubscribe = onAuthStateChanged(auth, (firebaseUser) => {
      if (!firebaseUser) {
        setUser(null);
        setCurrentView('AUTH');
      }
    });

    const handleAuthChange = () => {
      const newUser = getAuthUser();
      setUser(newUser);

      if (newUser) {
        if (newUser.role === 'ADMIN') setCurrentView('ADMIN_STORES');
        else if (newUser.role === 'MERCHANT') setCurrentView('MERCHANT');
        else setCurrentView('FEED');
      } else {
        setCurrentView('AUTH');
      }
    };

    handleAuthChange();
    window.addEventListener('auth_change', handleAuthChange);
    return () => {
      window.removeEventListener('auth_change', handleAuthChange);
      unsubscribe();
    };
  }, []);

  const handleOpenStoreProfile = async (storeId: string) => {
    const store = await getStoreById(storeId);
    if (store) {
      setSelectedStore(store);
      setCurrentView('STORE_PROFILE');
    }
  };

  const renderContent = () => {
    if (!user) return <AuthScreen />;

    switch (currentView) {
      case 'FEED': 
        return <FeedScreen onStoreClick={handleOpenStoreProfile} />;
      case 'EXPLORE': 
        return <ExploreScreen />;
      case 'MERCHANT': 
        return <MerchantDashboard onViewChange={setCurrentView} />;
      case 'PROFILE': 
        return <ProfileScreen />;
      case 'ADMIN_STORES': 
        return <AdminDashboard />;
      case 'STORE_PROFILE': 
        return selectedStore ? (
          <StoreProfileScreen 
            store={selectedStore} 
            onBack={() => setCurrentView('FEED')} 
          />
        ) : <FeedScreen onStoreClick={handleOpenStoreProfile} />;
      default: 
        return <FeedScreen onStoreClick={handleOpenStoreProfile} />;
    }
  };

  return (
    <div className="min-h-screen bg-neutral-950 flex justify-center items-center overflow-hidden">
      <div className="fixed inset-0 pointer-events-none opacity-20 overflow-hidden hidden sm:block">
        <div className="absolute top-[-10%] left-[-10%] w-[40%] h-[40%] bg-indigo-600 blur-[120px] rounded-full" />
        <div className="absolute bottom-[-10%] right-[-10%] w-[40%] h-[40%] bg-rose-600 blur-[120px] rounded-full" />
      </div>

      <Layout activeView={currentView} onViewChange={setCurrentView} user={user}>
        <div className="h-full w-full animate-fade-in">
          {renderContent()}
        </div>
      </Layout>
    </div>
  );
};

