  const categories = ['Alimentação', 'Moda', 'Beleza', 'Serviços', 'Eletrônicos'];

  const handleCreateStore = (e: React.FormEvent) => {
    e.preventDefault();
    const newStore: StoreType = {
      id: Date.now().toString(),
      ...formData,
      rating: 5.0,
      isPartner: true
    };
    saveStore(newStore);
