import React, { useState } from 'react';
import { Mail, Lock, User, Store, ArrowRight, Loader2, Sparkles, ShieldCheck, Info, Zap, ChevronLeft, MessageSquare, UserCircle } from 'lucide-react';
import { auth } from '../firebase';
import { 
  createUserWithEmailAndPassword, 
  signInWithEmailAndPassword 
} from 'https://www.gstatic.com/firebasejs/10.7.1/firebase-auth.js';
import { setAuthUser, saveUserMetadata, getUserMetadata } from '../constants';
import { UserRole } from '../types';

const AuthScreen: React.FC = () => {
  const [mode, setMode] = useState<'LOGIN' | 'SIGNUP'>('LOGIN');
  const [role, setRole] = useState<UserRole>('CONSUMER');
  const [loading, setLoading] = useState(false);

  const [formData, setFormData] = useState({
    name: '',
    email: '',
    password: ''
  });

  const handleGuestAccess = async () => {
    setLoading(true);
    // Simula um delay de rede para feedback visual
    await new Promise(r => setTimeout(r, 800));
    const guestUser = {
      id: 'guest_' + Math.random().toString(36).substr(2, 9),
      email: 'visitante@descontai.com',
      name: 'Visitante Sortudo',
      role: 'CONSUMER' as UserRole
    };
    setAuthUser(guestUser);
    setLoading(false);
  };

  const handleAuth = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);

    try {
      if (mode === 'SIGNUP') {
        const userCred = await createUserWithEmailAndPassword(auth, formData.email, formData.password);
        const newUser = {
          id: userCred.user.uid,
          email: formData.email,
          name: formData.name,
          role: 'CONSUMER' as UserRole
        };
        await saveUserMetadata(userCred.user.uid, newUser);
        setAuthUser(newUser);
      } else {
        const userCred = await signInWithEmailAndPassword(auth, formData.email, formData.password);
        const metadata = await getUserMetadata(userCred.user.uid);

        if (metadata) {
          setAuthUser(metadata);
        } else {
          setAuthUser({
            id: userCred.user.uid,
            email: formData.email,
            name: 'Usuário',
            role: 'CONSUMER'
          });
        }
      }
    } catch (error: any) {
      alert("Erro na autenticação: " + error.message);
    } finally {
      setLoading(false);
    }
  };

  const switchRole = (newRole: UserRole) => {
    setRole(newRole);
    setMode('LOGIN');
  };

  return (
    <div className="h-full w-full bg-white flex flex-col p-8 overflow-y-auto relative no-scrollbar">
      <div className="flex flex-col items-center mt-6 mb-8">
        <div className="w-16 h-16 bg-indigo-600 rounded-[22px] flex items-center justify-center shadow-2xl shadow-indigo-200 rotate-12 mb-5">
          <Sparkles className="text-white" size={32} />
        </div>
        <h1 className="text-3xl font-black text-gray-900 tracking-tighter italic">DESCONTAÍ</h1>
        <p className="text-gray-400 font-bold text-[10px] uppercase tracking-[0.3em] mt-1">Conectado ao Cloud</p>
      </div>

      <div className="bg-gray-100 p-1.5 rounded-2xl flex mb-8">
        <button 
          onClick={() => switchRole('CONSUMER')}
          className={`flex-1 py-3 rounded-xl text-[10px] font-black flex items-center justify-center gap-2 transition-all duration-300 ${role === 'CONSUMER' ? 'bg-white shadow-md text-indigo-600' : 'text-gray-400'}`}
        >
          <User size={14} /> CONSUMIDOR
        </button>
        <button 
          onClick={() => switchRole('MERCHANT')}
