interface FeedScreenProps {
  onStoreClick?: (storeId: string) => void;
}

const FeedScreen: React.FC<FeedScreenProps> = ({ onStoreClick }) => {
  const { promotions, loading: promoLoading, error, isUsingMock } = usePromotions();
  const [stores, setStores] = useState<Store[]>([]);
  const [storesLoading, setStoresLoading] = useState(true);

  useEffect(() => {
    const fetchStores = async () => {
      try {
        const allStores = await getStores();
        setStores(allStores.filter(s => s.isPartner));
      } catch (err) {
        console.error("Erro ao carregar lojas no feed:", err);
      } finally {
        setStoresLoading(false);
      }
    };
    fetchStores();
  }, []);

  const loading = promoLoading || storesLoading;

  if (loading) {
    return (
      <div className="h-full w-full flex flex-col items-center justify-center bg-black text-white gap-4">
        <div className="relative">
          <Loader2 size={48} className="animate-spin text-indigo-500" />
          <CloudLightning size={20} className="absolute inset-0 m-auto text-white animate-pulse" />
        </div>
        <p className="text-sm font-black uppercase tracking-[0.2em] animate-pulse text-center px-6 italic">
          Conectando à Cidade...
        </p>
      </div>
    );
  }

  return (
    <div className="h-full w-full bg-black overflow-y-scroll snap-y-mandatory no-scrollbar relative">
      <div className="absolute top-16 left-0 right-0 z-50 px-4 flex gap-4 overflow-x-auto no-scrollbar py-4 bg-gradient-to-b from-black/80 to-transparent">
        {stores.map((store) => (
          <button 
            key={store.id} 
            onClick={() => onStoreClick?.(store.id)}
            className="flex flex-col items-center gap-1.5 shrink-0 animate-fade-in group"
          >
            <div className="p-[2.5px] rounded-full bg-gradient-to-tr from-emerald-400 via-green-500 to-teal-400 shadow-[0_0_15px_rgba(52,211,153,0.3)] group-active:scale-95 transition-transform duration-200">
              <div className="p-0.5 bg-black rounded-full">
                <img 
                  src={store.logo} 
                  alt={store.name} 
                  className="w-14 h-14 rounded-full object-cover border-2 border-black"
                />
              </div>
            </div>
            <span className="text-[9px] text-white font-black uppercase tracking-tighter truncate w-16 text-center drop-shadow-md">
              {store.name.split(' ')[0]}
            </span>
          </button>
        ))}
      </div>

      {!isUsingMock && promotions.length > 0 && (
        <div className="absolute top-5 right-4 z-[60] bg-emerald-500/80 backdrop-blur-md px-2 py-1 rounded-md flex items-center gap-1.5 animate-fade-in border border-white/20 shadow-xl">
          <div className="w-1.5 h-1.5 bg-white rounded-full animate-ping" />
          <span className="text-white text-[9px] font-black uppercase tracking-tighter">AO VIVO</span>
        </div>
      )}

      {promotions.map((promo) => (
        <ReelCard key={promo.id} promotion={promo} />
      ))}

      {promotions.length === 0 && (
        <div className="h-full w-full flex flex-col items-center justify-center text-white p-8 text-center bg-neutral-900">
          <CloudLightning size={48} className="text-indigo-500 mb-4 opacity-50" />
          <h2 className="text-2xl font-black mb-2 tracking-tighter italic">CIDADE SILENCIOSA</h2>
          <p className="text-gray-400 text-sm">Nenhuma oferta ativa no momento. Seja o primeiro lojista a publicar!</p>
        </div>
      )}

      <div className="h-[1px]" />
    </div>
  );
};

export default FeedScreen;

