const AdminDashboard: React.FC = () => {
  const [stores, setStores] = useState<StoreType[]>([]);
  const [loading, setLoading] = useState(true);
  const [showModal, setShowModal] = useState(false);
  const [formData, setFormData] = useState({
    name: '',
    category: 'Alimentação',
    address: '',
    ownerEmail: '',
    logo: 'https://images.unsplash.com/photo-1441986300917-64674bd600d8?w=100&h=100&fit=crop'
  });

  const categories = ['Alimentação', 'Moda', 'Beleza', 'Serviços', 'Eletrônicos'];

  const fetchAllStores = async () => {
    setLoading(true);
    try {
      const data = await getStores();
      setStores(data);
    } catch (err) {
      console.error("Erro ao listar lojas no admin:", err);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchAllStores();
  }, []);

  const handleCreateStore = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    const newStore: Partial<StoreType> = {
      ...formData,
      rating: 5.0,
      isPartner: true
    };

    try {
      await saveStore(newStore);
      await fetchAllStores();
      setShowModal(false);
      setFormData({
        name: '', category: 'Alimentação', address: '', ownerEmail: '',
        logo: 'https://images.unsplash.com/photo-1441986300917-64674bd600d8?w=100&h=100&fit=crop'
      });
    } catch (err) {
      alert("Erro ao salvar parceiro.");
    } finally {
      setLoading(false);
    }
  };

  const handleLogoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setFormData({...formData, logo: reader.result as string});
      reader.readAsDataURL(file);
    }
  };

  const handleLogout = () => {
    if (confirm("Deseja sair do painel administrativo?")) {
      setAuthUser(null);
    }
  };

  return (
    <div className="p-4 h-full bg-gray-50 overflow-y-auto pb-24 text-left">
      <div className="mb-8 flex justify-between items-center">
        <div>
          <h1 className="text-2xl font-bold text-gray-800">Gestão de Parceiros</h1>
          <p className="text-xs text-gray-400 font-bold uppercase tracking-widest mt-1 italic">Painel do Idealizador</p>
        </div>
        <div className="flex items-center gap-2">
          <button 
            onClick={handleLogout}
            title="Sair"
            className="bg-white p-2.5 rounded-2xl border border-gray-200 shadow-sm text-gray-400 hover:text-rose-600 transition-colors"
          >
            <LogOut size={20} />
