          <button 
            onClick={() => setShowModal(true)}
            className="bg-indigo-600 text-white p-3 rounded-2xl shadow-lg shadow-indigo-100"
          >
            <Plus size={24} />
          </button>
        </div>
      </div>

      <div className="space-y-4">
        {stores.map(store => (
          <div key={store.id} className="bg-white p-4 rounded-3xl border border-gray-100 shadow-sm flex items-center gap-4">
            <img src={store.logo} className="w-14 h-14 rounded-2xl object-cover" alt={store.name} />
            <div className="flex-1">
              <h3 className="font-black text-gray-800">{store.name}</h3>
              <div className="flex items-center gap-1 text-[10px] text-gray-400 font-bold uppercase">
                <Mail size={10} /> {store.ownerEmail}
              </div>
            </div>
            <div className="bg-green-50 p-2 rounded-full text-green-500">
              <UserCheck size={18} />
            </div>
          </div>
        ))}
        {loading && !showModal && <div className="flex justify-center p-8"><Loader2 className="animate-spin text-indigo-500" size={32} /></div>}
      </div>

      {showModal && (
        <div className="fixed inset-0 z-[120] bg-black/80 flex items-center justify-center p-4 backdrop-blur-md">
          <div className="bg-white w-full max-w-sm rounded-3xl p-6 relative overflow-y-auto max-h-[90vh]">
            <button onClick={() => setShowModal(false)} className="absolute top-4 right-4 text-gray-400 p-2">
              <X size={24} />
            </button>
            <h3 className="text-xl font-bold mb-6">Nova Empresa Parceira</h3>

            <form onSubmit={handleCreateStore} className="space-y-4">
