  const [loading, setLoading] = useState(false);

  const [formData, setFormData] = useState({
    name: '',
    email: '',
    password: ''
  });

  const handleGuestAccess = async () => {
    setLoading(true);
    await new Promise(r => setTimeout(r, 800));
    const guestUser: AuthUser = {
      id: 'guest_' + Math.random().toString(36).substr(2, 9),
      email: 'visitante@descontai.com',
      name: 'Visitante Sortudo',
      role: 'CONSUMER'
    };
    setAuthUser(guestUser);
    setLoading(false);
  };

  const handleAuth = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);

    // --- LÓGICA DE ACESSO MESTRE (DEVELOPER MODE) ---
    const isMasterAdmin = formData.email === 'admin@descontai.com' && formData.password === 'admin123';
    const isMasterMerchant = formData.email === 'loja@descontai.com' && formData.password === 'loja123';

    if (mode === 'LOGIN' && (isMasterAdmin || isMasterMerchant)) {
      await new Promise(r => setTimeout(r, 1000)); // Simula delay
      const masterUser: AuthUser = {
        id: isMasterAdmin ? 'master_admin' : 'master_merchant',
        email: formData.email,
        name: isMasterAdmin ? 'Idealizador Master' : 'Lojista Demo',
        role: isMasterAdmin ? 'ADMIN' : 'MERCHANT',
        merchantId: isMasterMerchant ? 'store_demo_1' : undefined
      };
      setAuthUser(masterUser);
      setLoading(false);
      return;
    }
    // ------------------------------------------------

    try {
      if (mode === 'SIGNUP') {
        const userCred = await createUserWithEmailAndPassword(auth, formData.email, formData.password);
        const newUser: AuthUser = {
          id: userCred.user.uid,
          email: formData.email,
          name: formData.name,
          role: 'CONSUMER'
        };
        await saveUserMetadata(userCred.user.uid, newUser);
        setAuthUser(newUser);
      } else {
        const userCred = await signInWithEmailAndPassword(auth, formData.email, formData.password);
        const metadata = await getUserMetadata(userCred.user.uid);

        if (metadata) {
          setAuthUser(metadata);
        } else {
          setAuthUser({
            id: userCred.user.uid,
            email: formData.email,
            name: 'Usuário',
            role: 'CONSUMER'
          });
        }
      }
    } catch (error: any) {
      // Se o Firebase não estiver configurado, avisa o usuário mas permite erro controlado
      if (error.message.includes('apiKey')) {
        alert("Configuração do Firebase ausente no arquivo firebase.ts.\n\nPara testar agora, use:\nAdmin: admin@descontai.com / admin123\nLojista: loja@descontai.com / loja123");
      } else {
        alert("Erro: " + error.message);
      }
    } finally {
      setLoading(false);
    }
  };

  const switchRole = (newRole: UserRole) => {
    setRole(newRole);
    setMode('LOGIN');
  };

  return (
    <div className="h-full w-full bg-white flex flex-col p-8 overflow-y-auto relative no-scrollbar">
      <div className="flex flex-col items-center mt-6 mb-8">
        <div className="w-16 h-16 bg-indigo-600 rounded-[22px] flex items-center justify-center shadow-2xl shadow-indigo-200 rotate-12 mb-5">
          <Sparkles className="text-white" size={32} />
        </div>
        <h1 className="text-3xl font-black text-gray-900 tracking-tighter italic">DESCONTAÍ</h1>
        <p className="text-gray-400 font-bold text-[10px] uppercase tracking-[0.3em] mt-1">Nuvem Habilitada</p>
      </div>

      <div className="bg-gray-100 p-1.5 rounded-2xl flex mb-8">
        <button 
          onClick={() => switchRole('CONSUMER')}
          className={`flex-1 py-3 rounded-xl text-[10px] font-black flex items-center justify-center gap-2 transition-all duration-300 ${role === 'CONSUMER' ? 'bg-white shadow-md text-indigo-600' : 'text-gray-400'}`}
        >
          <User size={14} /> CONSUMIDOR
        </button>
        <button 
          onClick={() => switchRole('MERCHANT')}
          className={`flex-1 py-3 rounded-xl text-[10px] font-black flex items-center justify-center gap-2 transition-all duration-300 ${role === 'MERCHANT' ? 'bg-white shadow-md text-indigo-600' : 'text-gray-400'}`}
        >
          <Store size={14} /> LOJISTA
        </button>
      </div>

      <div className="flex flex-col flex-1">
        {role === 'MERCHANT' && mode === 'SIGNUP' ? (
          <div className="flex-1 flex flex-col items-center justify-center text-center animate-fade-in">
            <div className="w-20 h-20 bg-amber-50 rounded-full flex items-center justify-center text-amber-500 mb-6 border border-amber-100">
              <ShieldCheck size={40} />
            </div>
            <h2 className="text-xl font-black text-gray-900 mb-3 tracking-tight">ACESSO PARCEIRO</h2>
            <p className="text-sm text-gray-500 font-medium leading-relaxed mb-8 px-4">
              Para cadastrar sua loja, use as credenciais demo ou entre em contato.
            </p>
            <div className="bg-indigo-50 p-4 rounded-2xl mb-6 w-full text-left">
              <p className="text-[10px] font-black text-indigo-400 uppercase mb-2">Credenciais Demo:</p>
              <p className="text-xs font-bold text-indigo-900">E-mail: loja@descontai.com</p>
              <p className="text-xs font-bold text-indigo-900">Senha: loja123</p>
            </div>
            <button 
              onClick={() => window.open('https://wa.me/5511999999999', '_blank')}
              className="w-full bg-emerald-500 py-4 rounded-2xl text-white font-black text-sm flex items-center justify-center gap-3 shadow-xl shadow-emerald-100 mb-4"
            >
              <MessageSquare size={18} /> SUPORTE COMERCIAL
            </button>
            <button onClick={() => setMode('LOGIN')} className="text-[11px] font-black text-gray-400 uppercase tracking-widest flex items-center gap-2">
              <ChevronLeft size={14} /> Voltar para Login
            </button>
          </div>
        ) : (
          <div className="animate-fade-in">
            <div className="mb-6 flex justify-between items-end">
              <h2 className="text-2xl font-black text-gray-900 tracking-tight italic leading-none">
                {mode === 'LOGIN' ? 'ENTRAR' : 'CADASTRAR'}
              </h2>
              {role === 'CONSUMER' && (
                 <span className="text-[9px] font-black text-indigo-500 bg-indigo-50 px-2 py-1 rounded-md uppercase">Comunidade</span>
              )}
              {role === 'MERCHANT' && (
                 <span className="text-[9px] font-black text-amber-500 bg-amber-50 px-2 py-1 rounded-md uppercase">Business</span>
              )}
            </div>

            <form onSubmit={handleAuth} className="space-y-4">
              {mode === 'SIGNUP' && (
                <div className="relative group">
                  <User className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
                  <input required placeholder="Nome Completo" className="w-full bg-gray-50 border border-gray-100 rounded-2xl py-4 pl-12 pr-4 text-sm font-medium outline-none focus:ring-2 focus:ring-indigo-500/20" 
                    value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} />
                </div>
              )}
              <div className="relative group">
                <Mail className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
                <input required type="email" placeholder="E-mail" className="w-full bg-gray-50 border border-gray-100 rounded-2xl py-4 pl-12 pr-4 text-sm font-medium outline-none focus:ring-2 focus:ring-indigo-500/20" 
                  value={formData.email} onChange={e => setFormData({...formData, email: e.target.value})} />
              </div>
              <div className="relative group">
                <Lock className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400" size={18} />
                <input required type="password" placeholder="Senha" className="w-full bg-gray-50 border border-gray-100 rounded-2xl py-4 pl-12 pr-4 text-sm font-medium outline-none focus:ring-2 focus:ring-indigo-500/20" 
                  value={formData.password} onChange={e => setFormData({...formData, password: e.target.value})} />
              </div>

              <button disabled={loading} className="w-full bg-indigo-600 py-4 rounded-2xl text-white font-black text-sm flex items-center justify-center gap-3 shadow-2xl shadow-indigo-200 disabled:opacity-50 mt-4 active:scale-95 transition-transform">
                {loading ? <Loader2 className="animate-spin" size={20} /> : <>{mode === 'LOGIN' ? 'ACESSAR AGORA' : 'CRIAR MINHA CONTA'} <ArrowRight size={18} /></>}
              </button>
            </form>

            <div className="mt-8 flex flex-col gap-4">
              <button onClick={() => setMode(mode === 'LOGIN' ? 'SIGNUP' : 'LOGIN')} className="w-full text-center text-[10px] font-black text-gray-400 uppercase tracking-[0.2em]">
                {mode === 'LOGIN' ? 'Novo por aqui? Criar conta' : 'Já tem acesso? Fazer Login'}
              </button>

              {role === 'CONSUMER' && (
                <>
                  <div className="flex items-center gap-4">
                    <div className="flex-1 h-[1px] bg-gray-100"></div>
                    <span className="text-[10px] font-black text-gray-300 uppercase italic">ou</span>
                    <div className="flex-1 h-[1px] bg-gray-100"></div>
                  </div>

                  <button 
                    onClick={handleGuestAccess}
                    disabled={loading}
                    className="w-full bg-white border-2 border-gray-100 py-4 rounded-2xl text-gray-900 font-black text-[11px] flex items-center justify-center gap-3 shadow-sm hover:border-indigo-100 transition-all uppercase tracking-widest active:scale-95"
                  >
                    <UserCircle size={18} className="text-indigo-500" />
                    Explorar como Visitante
                  </button>
                </>
              )}

              {role === 'MERCHANT' && (
                <p className="text-center text-[9px] text-gray-400 font-medium px-4">
                  Acesso exclusivo para lojistas parceiros. <br/>Não possui uma loja? <button onClick={() => switchRole('CONSUMER')} className="text-indigo-500 font-bold">Volte ao início.</button>
                </p>
              )}
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default AuthScreen;
